    // ==========================================
    // 数据库初始化 - Dexie.js (精简版 V38)
    // 移除了所有未使用的表，仅保留核心功能
    // ==========================================
    const db = new Dexie('MobileSimulatorDB'); 

   /*
     * 数据结构说明：
     * chats表同时存储角色和聊天记录
     * - 角色：!isGroup && !linkedCharacterData
     * - 聊天：!isGroup && linkedCharacterData
     * pp_merged.js筛选：filter(chat => !chat.isGroup && !chat.linkedCharacterData)
     */

    // ==========================================
    // 数据库版本管理（每个版本完整列出所有表）
    // ==========================================

    // V1: 初始版本 - 核心表结构（14张表）
    db.version(1).stores({
      // 聊天相关表（4张）
      chats: '&id, profileId, isGroup',                    // 角色和聊天记录（混合存储，通过linkedCharacterData区分）
      chatSettings: '&characterId',                         // 聊天设置（每个角色独立的聊天配置）
      chatMessages: '++id, characterId, sessionId, [characterId+sessionId], timestamp',  // 聊天消息记录
      chatSessions: '++id, characterId, chatId, isActive, syncToX',  // 多会话管理（支持多个独立对话）

      // 角色数据表（4张）
      characterSchedules: '&id, characterId, sessionId, [characterId+sessionId]',  // 角色日程安排
      characterAffection: '&id, characterId, sessionId, [characterId+sessionId]',  // 角色好感度系统
      characterDiary: '++id, characterId, sessionId, profileId, [characterId+sessionId+profileId], date, type, createdAt',  // 角色日记本
      characterAlbums: '&characterId, createdAt, updatedAt',  // 角色相册（存储照片等媒体）

      // 通讯相关表（1张）
      phoneNumbers: '&id, characterId, number',             // 电话号码绑定

      // 全局配置表（5张）
      apiConfig: '&id',                                     // API配置（存储API密钥等）
      globalSettings: '&id',                                // 全局设置（系统级配置）
      worldBooks: '&id, name',                              // 世界书（背景设定）
      apiPresets: '++id, name',                             // API预设模板
      userProfiles: '&id, name, createdAt'                  // 用户档案（多用户支持）
    });

    // V2: 添加通话记录表（15张表）
    db.version(2).stores({
      // 聊天相关表（4张）
      chats: '&id, profileId, isGroup',
      chatSettings: '&characterId',
      chatMessages: '++id, characterId, sessionId, [characterId+sessionId], timestamp',
      chatSessions: '++id, characterId, chatId, isActive, syncToX',

      // 角色数据表（4张）
      characterSchedules: '&id, characterId, sessionId, [characterId+sessionId]',
      characterAffection: '&id, characterId, sessionId, [characterId+sessionId]',
      characterDiary: '++id, characterId, sessionId, profileId, [characterId+sessionId+profileId], date, type, createdAt',
      characterAlbums: '&characterId, createdAt, updatedAt',

      // 通讯相关表（2张 - 新增callRecords）
      phoneNumbers: '&id, characterId, number',
      callRecords: '++id, phoneNumber, characterId, timestamp, callType',  // 📞 通话记录（来电/去电/未接）

      // 全局配置表（5张）
      apiConfig: '&id',
      globalSettings: '&id',
      worldBooks: '&id, name',
      apiPresets: '++id, name',
      userProfiles: '&id, name, createdAt'
    });

    // V3: 添加通讯录表（16张表 - 当前版本）
    db.version(3).stores({
      // 聊天相关表（4张）
      chats: '&id, profileId, isGroup',
      chatSettings: '&characterId',
      chatMessages: '++id, characterId, sessionId, [characterId+sessionId], timestamp',
      chatSessions: '++id, characterId, chatId, isActive, syncToX',

      // 角色数据表（4张）
      characterSchedules: '&id, characterId, sessionId, [characterId+sessionId]',
      characterAffection: '&id, characterId, sessionId, [characterId+sessionId]',
      characterDiary: '++id, characterId, sessionId, profileId, [characterId+sessionId+profileId], date, type, createdAt',
      characterAlbums: '&characterId, createdAt, updatedAt',

      // 通讯相关表（3张 - 新增contacts）
      phoneNumbers: '&id, characterId, number',
      callRecords: '++id, phoneNumber, characterId, timestamp, callType',
      contacts: '&phoneNumber, characterId, createdAt',     // 📱 通讯录（快速拨号和联系人管理）

      // 全局配置表（5张）
      apiConfig: '&id',
      globalSettings: '&id',
      worldBooks: '&id, name',
      apiPresets: '++id, name',
      userProfiles: '&id, name, createdAt'
    });

    window.db = db;
    console.log('✅ 数据库初始化完成');

    // ==========================================
    // 🔧 核心ID工具函数（只需4个，简单有效）
    // ==========================================

    /**
     * 生成角色ID（新创建时使用）
     * 格式: char_时间戳_随机字符
     */
    function generateCharacterId() {
      return `char_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
    }

    /**
     * 标准化ID（统一处理类型和空格）
     */
    function normalizeId(id) {
      if (id === null || id === undefined) return '';
      return String(id).trim();
    }

    /**
     * 比较两个ID是否相同
     */
    function isSameId(id1, id2) {
      return normalizeId(id1) === normalizeId(id2);
    }

    /**
     * 从chat记录获取角色ID
     * 规则：角色记录用chat.id，聊天记录用linkedCharacterData.id
     */
    function getCharacterIdFromChat(chat) {
      if (!chat) return '';
      // 聊天记录：从linkedCharacterData获取
      if (chat.linkedCharacterData) {
        return normalizeId(chat.linkedCharacterData.id);
      }
      // 角色记录：chat.id就是角色ID
      return normalizeId(chat.id);
    }

    /**
     * 生成聊天ID（创建聊天记录时使用）
     */
    function generateChatId() {
      return `chat_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
    }

    /**
     * 判断是否是聊天记录（有linkedCharacterData的）
     */
    function isChatRecord(chat) {
      return chat && chat.linkedCharacterData;
    }

    /**
     * 根据ID获取角色（从chats表查询）
     */
    async function getCharacterById(characterId) {
      const id = normalizeId(characterId);
      if (!id) return null;

      // 从chats表查询角色记录
      const allChats = await db.chats.toArray();

      // 查找角色记录（没有linkedCharacterData的）
      const charRecord = allChats.find(c =>
        !c.isGroup && !c.linkedCharacterData && isSameId(c.id, id)
      );
      if (charRecord) return charRecord;

      // 查找聊天记录中嵌套的角色数据
      const chatRecord = allChats.find(c =>
        c.linkedCharacterData && isSameId(c.linkedCharacterData.id, id)
      );
      if (chatRecord) return chatRecord.linkedCharacterData;

      return null;
    }

    /**
     * 🔥 同步更新所有相关聊天的linkedCharacterData
     * 当角色资料在角色app中被修改后，需要同步到所有使用该角色的聊天记录
     */
    async function syncLinkedCharacterData(characterId, updatedData) {
      const cleanCharId = normalizeId(characterId);
      if (!cleanCharId) return;

      try {
        // 获取所有聊天记录
        const allChats = await db.chats.toArray();

        // 找到所有使用该角色的聊天记录
        const relatedChats = allChats.filter(chat =>
          chat.linkedCharacterData &&
          isSameId(chat.linkedCharacterData.id, cleanCharId)
        );

        if (relatedChats.length === 0) {
          console.log('📭 没有找到相关聊天记录需要同步');
          return;
        }

        // 批量更新
        for (const chat of relatedChats) {
          chat.linkedCharacterData = {
            ...chat.linkedCharacterData,
            id: cleanCharId,
            name: updatedData.name,
            originalName: updatedData.originalName || updatedData.name,
            settings: {
              ...chat.linkedCharacterData.settings,
              ...updatedData.settings
            },
            // 🔥 同步百宝书绑定（如果有的话）
            ...(updatedData.boundBaobaobooks !== undefined ? { boundBaobaobooks: updatedData.boundBaobaobooks } : {})
          };
          await db.chats.put(chat);
        }

        console.log(`✅ 已同步更新 ${relatedChats.length} 个聊天记录的角色资料`);
      } catch (error) {
        console.error('❌ 同步linkedCharacterData失败:', error);
      }
    }

    console.log('🔧 ID工具函数已加载');

    // ==========================================
    // 🔥 增量更新工具函数（避免全量刷新）
    // ==========================================

    // 只更新单个聊天列表项的最后消息（不刷新整个列表）
    function updateChatListItemLastMessage(chatId, lastMessage, timestamp) {
      const chatItem = document.querySelector(`.chat-item-mini[data-chat-id="${chatId}"]`);
      if (!chatItem) return false;

      const previewEl = chatItem.querySelector('.chat-preview-mini');
      const timeEl = chatItem.querySelector('.chat-time-mini');

      if (previewEl) previewEl.textContent = lastMessage || 'No messages yet';
      if (timeEl) timeEl.textContent = timestamp ? formatChatTime(timestamp) : '';

      return true;
    }

    // 只移除DOM中的指定消息（不重新渲染整个消息列表）
    function removeChatMessagesFromDOM(messageIndices) {
      const messagesArea = document.getElementById('chatMessagesArea');
      if (!messagesArea) return;

      // 按索引从大到小排序，这样删除时不会影响其他索引
      const sortedIndices = [...messageIndices].sort((a, b) => b - a);

      sortedIndices.forEach(index => {
        const msgEl = messagesArea.querySelector(`.chat-message-group[data-message-index="${index}"]`);
        if (msgEl) msgEl.remove();
      });

      // 重新编号剩余消息的索引
      reindexMessageElements();
    }

    // 重新编号消息元素的索引（删除消息后调用）
    function reindexMessageElements() {
      const messagesArea = document.getElementById('chatMessagesArea');
      if (!messagesArea) return;

      const messages = messagesArea.querySelectorAll('.chat-message-group');
      messages.forEach((msg, index) => {
        msg.dataset.messageIndex = index;
        // 更新checkbox的onclick属性
        const checkbox = msg.querySelector('.message-checkbox');
        if (checkbox) {
          checkbox.setAttribute('onclick', `chatToggleMessageSelection(${index})`);
        }
      });
    }

    // 移除从指定索引开始的所有消息（用于重回功能）
    function removeMessagesFromIndex(startIndex) {
      const messagesArea = document.getElementById('chatMessagesArea');
      if (!messagesArea) return;

      const messages = messagesArea.querySelectorAll('.chat-message-group');
      messages.forEach(msg => {
        const idx = parseInt(msg.dataset.messageIndex);
        if (idx >= startIndex) {
          msg.remove();
        }
      });

      // 不需要重新编号，因为只删除了尾部的消息
    }

    // 只更新单个聊天列表项的名称（不刷新整个列表）
    function updateChatListItemName(chatId, newName) {
      const chatItem = document.querySelector(`.chat-item-mini[data-chat-id="${chatId}"]`);
      if (!chatItem) return false;

      const nameEl = chatItem.querySelector('.chat-name-mini');
      if (nameEl) nameEl.textContent = newName;

      return true;
    }

    // 只更新聊天会话的active状态（不重新渲染整个列表）
    function updateChatSessionsActiveState(newActiveSessionId) {
      const container = document.getElementById('chatSessionsList');
      if (!container) return false;

      const sessionCards = container.querySelectorAll('.chat-session-card-v2');
      sessionCards.forEach(card => {
        // 从onclick属性中提取sessionId
        const onclick = card.getAttribute('onclick') || '';
        const match = onclick.match(/switchChatSession\('([^']+)'/);
        const cardSessionId = match ? match[1] : '';

        // 更新active状态
        if (cardSessionId === newActiveSessionId) {
          card.classList.add('active');
          const meta = card.querySelector('.chat-session-meta-v2');
          if (meta) meta.textContent = '当前激活';
        } else {
          card.classList.remove('active');
          const meta = card.querySelector('.chat-session-meta-v2');
          if (meta && meta.textContent === '当前激活') {
            meta.textContent = '点击切换';
          }
        }
      });

      return true;
    }

    console.log('🔧 增量更新工具函数已加载');

    // ==========================================
    // 🔥 消息类型处理工具函数（统一处理，避免重复代码）
    // ==========================================

    // 将内存中的消息转换为数据库格式（统一处理所有消息类型）
    function convertMessageToDbFormat(msg, characterId, sessionId) {
      const dbMsg = {
        characterId: normalizeId(characterId),
        sessionId: normalizeId(sessionId) || 'default',
        role: msg.role,
        timestamp: new Date(msg.timestamp).toISOString()
      };

      // 根据消息类型添加对应字段
      if (msg.type === 'call') {
        // 🔥 通话记录消息
        dbMsg.type = 'call';
        dbMsg.content = msg.content;
        dbMsg.callType = msg.callType;
        dbMsg.callStatus = msg.callStatus;
        dbMsg.callStartTime = msg.callStartTime;
        dbMsg.callEndTime = msg.callEndTime;
        dbMsg.callDuration = msg.callDuration;
        dbMsg.phoneNumber = msg.phoneNumber;
        dbMsg.callTranscript = msg.callTranscript;
      } else if (msg.type === 'sticker') {
        // 表情包消息（加载后的格式）
        dbMsg.type = 'sticker';
        dbMsg.content = msg.content;
        dbMsg.url = msg.url;
        dbMsg.description = msg.description;
      } else if (msg.sticker) {
        // 表情包消息（刚发送时的格式）
        dbMsg.content = msg.content;
        dbMsg.sticker = msg.sticker;
      } else if (msg.image) {
        // 图片消息
        dbMsg.content = msg.content || '[图片]';
        dbMsg.image = msg.image;
      } else if (msg.type === 'text-image') {
        // 文字图消息
        dbMsg.type = 'text-image';
        dbMsg.content = msg.content;
        dbMsg.imageDescription = msg.imageDescription;
      } else if (msg.type === 'html-card') {
        // HTML卡片消息
        dbMsg.type = 'html-card';
        dbMsg.content = msg.content;
      } else {
        // 普通文字消息
        dbMsg.content = msg.content;
      }

      return dbMsg;
    }

    // 将数据库消息转换为chatbox格式（从数据库加载时使用）
    function convertDbMessageToChatbox(msg) {
      const historyMsg = {
        role: msg.role,
        content: msg.content || '',
        timestamp: new Date(msg.timestamp).getTime(),
        read: true,
        // 🔥 保留数据库消息ID和反应，用于反应功能
        _dbMessageId: msg.id,
        reaction: msg.reaction || null,
        aiReaction: msg.aiReaction || null,  // 🔥 AI贴的反应
        // 🔥 保留引用回复信息
        replyTo: msg.replyTo || null
      };

      // 处理特殊类型消息
      if (msg.type === 'call') {
        historyMsg.type = 'call';
        historyMsg.callTranscript = msg.callTranscript || [];
        historyMsg.callStartTime = msg.callStartTime;
        historyMsg.callEndTime = msg.callEndTime;
        historyMsg.callDuration = msg.callDuration;
        historyMsg.phoneNumber = msg.phoneNumber;
      } else if (msg.type === 'text-image') {
        historyMsg.type = 'text-image';
        historyMsg.imageDescription = msg.imageDescription;
      } else if (msg.type === 'sticker' || msg.sticker) {
        historyMsg.type = 'sticker';
        historyMsg.url = msg.url || msg.sticker?.url;
        historyMsg.description = msg.description || msg.sticker?.description;
      } else if (msg.type === 'html-card') {
        historyMsg.type = 'html-card';
      } else if (msg.image) {
        historyMsg.image = msg.image;
      }

      return historyMsg;
    }

    // 获取消息的显示文本（用于聊天列表预览）
    function getMessageDisplayText(msg) {
      if (!msg) return '';

      if (msg.type === 'call') {
        return `[通话] ${msg.content || ''}`;
      } else if (msg.type === 'sticker' || msg.sticker) {
        return '[表情包]';
      } else if (msg.type === 'text-image') {
        return msg.content || '[图片描述]';
      } else if (msg.type === 'html-card') {
        return '[卡片]';
      } else if (msg.image) {
        return '[图片]';
      } else {
        return msg.content || '';
      }
    }

    // 批量同步chatbox到数据库（先清空再重新添加）
    // 🔥 注意：保留通话记录（type='call'），因为通话记录不在chatbox中
    async function syncChatboxToDatabase(chatbox, characterId, sessionId) {
      const cleanCharacterId = normalizeId(characterId);
      const cleanSessionId = normalizeId(sessionId) || 'default';

      // 第一步：删除该会话的所有消息（🔥 但保留通话记录！）
      const allDbMessages = await db.chatMessages.toArray();
      const messagesToDelete = allDbMessages.filter(m =>
        isSameId(m.characterId, cleanCharacterId) &&
        isSameId(m.sessionId || 'default', cleanSessionId) &&
        m.type !== 'call'  // 🔥 跳过通话记录，不删除
      );

      for (const msg of messagesToDelete) {
        await db.chatMessages.delete(msg.id);
      }
      console.log(`🗑️ 已清空 ${messagesToDelete.length} 条数据库消息（保留通话记录）`);

      // 第二步：重新添加所有消息（跳过通话记录，因为它们已经保留了）
      for (const msg of chatbox) {
        // 🔥 跳过chatbox中可能存在的通话记录（避免重复添加）
        if (msg.type === 'call') continue;

        const dbMsg = convertMessageToDbFormat(msg, cleanCharacterId, cleanSessionId);
        await db.chatMessages.add(dbMsg);
      }
      console.log(`✅ 已重新添加 ${chatbox.length} 条消息到数据库`);
    }

    console.log('🔧 消息类型处理工具函数已加载');

    // ==========================================
    // 全局世界观管理
    // ==========================================

    // 加载世界观设置
    async function loadWorldview() {
      try {
        const settings = await db.globalSettings.get('worldview');
        if (settings) {
          document.getElementById('worldviewName').value = settings.name || '';
          document.getElementById('worldviewDesc').value = settings.description || '';
        }
      } catch (error) {
        console.error('加载世界观失败:', error);
      }
    }

    // 保存世界观设置
    async function saveWorldview() {
      try {
        const name = document.getElementById('worldviewName').value.trim();
        const description = document.getElementById('worldviewDesc').value.trim();

        if (!name) {
          showIslandNotification('错误', '请输入世界观名称', 'info');
          return;
        }

        await db.globalSettings.put({
          id: 'worldview',
          name: name,
          description: description,
          updatedAt: new Date().toISOString()
        });

        showIslandNotification('成功', '世界观已保存', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('保存世界观失败:', error);
        showIslandNotification('错误', '保存失败', 'info');
      }
    }

    // 清空世界观设置
    function clearWorldview() {
      document.getElementById('worldviewName').value = '';
      document.getElementById('worldviewDesc').value = '';
      showIslandNotification('已清空', '世界观设置已清空', 'info');
    }

    // ==========================================
    // 知识库管理 (CRUD)
    // ==========================================

    // 渲染知识库列表
    async function renderKnowledgeList() {
      try {
        const knowledgeList = document.getElementById('knowledgeList');
        const items = await db.worldBooks.toArray();

        if (items.length === 0) {
          knowledgeList.innerHTML = `
            <div class="empty-state">
              <svg class="empty-state-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M19 3H5a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2V5a2 2 0 00-2-2zM9 17H7v-2h2v2zm0-4H7v-2h2v2zm0-4H7V7h2v2zm8 8h-6v-2h6v2zm0-4h-6v-2h6v2zm0-4h-6V7h6v2z" stroke-linecap="round" />
              </svg>
              <div class="empty-state-text">还没有知识条目<br/>点击上方按钮添加</div>
            </div>
          `;
          return;
        }

        knowledgeList.innerHTML = items.map(item => `
          <div class="knowledge-item" onclick="editKnowledge('${item.id}')">
            <div class="knowledge-item-info">
              <div class="knowledge-item-name">${item.name}</div>
              <div class="knowledge-item-category">${getCategoryName(item.categoryId)}</div>
            </div>
            <div class="knowledge-item-actions">
              <div class="knowledge-item-btn" onclick="event.stopPropagation(); editKnowledge('${item.id}')" title="编辑">
                <svg viewBox="0 0 24 24">
                  <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z" stroke-linecap="round" />
                </svg>
              </div>
              <div class="knowledge-item-btn" onclick="event.stopPropagation(); deleteKnowledge('${item.id}')" title="删除">
                <svg viewBox="0 0 24 24">
                  <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2" stroke-linecap="round" />
                </svg>
              </div>
            </div>
          </div>
        `).join('');
      } catch (error) {
        console.error('渲染知识库列表失败:', error);
      }
    }

    // 获取分类名称
    function getCategoryName(categoryId) {
      const categories = {
        'location': '地点',
        'race': '种族',
        'important': '重要信息',
        'character': '角色',
        'item': '物品',
        'event': '事件',
        'custom': '自定义'
      };
      return categories[categoryId] || '未分类';
    }

    // 显示添加知识条目模态框
    function showAddKnowledgeModal() {
      const modal = document.getElementById('knowledgeModal');
      const form = document.getElementById('knowledgeForm');

      // 清空表单
      document.getElementById('knowledgeId').value = '';
      document.getElementById('knowledgeName').value = '';
      document.getElementById('knowledgeCategory').value = 'location';
      document.getElementById('knowledgeContent').value = '';
      document.getElementById('knowledgeModalTitle').textContent = '添加知识条目';

      document.getElementById('modalOverlay').classList.add('active');
      modal.classList.add('active');
    }

    // 编辑知识条目
    async function editKnowledge(id) {
      try {
        const item = await db.worldBooks.get(id);
        if (!item) return;

        document.getElementById('knowledgeId').value = item.id;
        document.getElementById('knowledgeName').value = item.name;
        document.getElementById('knowledgeCategory').value = item.categoryId;
        document.getElementById('knowledgeContent').value = item.content || '';
        document.getElementById('knowledgeModalTitle').textContent = '编辑知识条目';

        const modal = document.getElementById('knowledgeModal');
        document.getElementById('modalOverlay').classList.add('active');
        modal.classList.add('active');
      } catch (error) {
        console.error('加载知识条目失败:', error);
      }
    }

    // 保存知识条目
    async function saveKnowledge() {
      try {
        const id = document.getElementById('knowledgeId').value;
        const name = document.getElementById('knowledgeName').value.trim();
        const categoryId = document.getElementById('knowledgeCategory').value;
        const content = document.getElementById('knowledgeContent').value.trim();

        if (!name) {
          showIslandNotification('错误', '请输入条目名称', 'info');
          return;
        }

        const data = {
          id: id || `kb_${Date.now()}`,
          name: name,
          categoryId: categoryId,
          content: content,
          updatedAt: new Date().toISOString()
        };

        await db.worldBooks.put(data);
        await renderKnowledgeList();
        closeKnowledgeModal();

        showIslandNotification('成功', id ? '知识条目已更新' : '知识条目已添加', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('保存知识条目失败:', error);
        showIslandNotification('错误', '保存失败', 'info');
      }
    }

    // 删除知识条目
    async function deleteKnowledge(id) {
      try {
        const confirmed = confirm('确定要删除这个知识条目吗？');
        if (!confirmed) return;

        await db.worldBooks.delete(id);
        await renderKnowledgeList();

        showIslandNotification('已删除', '知识条目已删除', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('删除知识条目失败:', error);
      }
    }

    // 关闭知识条目模态框
    function closeKnowledgeModal() {
      const modal = document.getElementById('knowledgeModal');
      document.getElementById('modalOverlay').classList.remove('active');
      modal.classList.remove('active');
    }

    // ==========================================
    // 全量数据导出导入
    // ==========================================

    /**
     * 导出全部手机数据
     * 包含所有数据库表的完整数据
     */
    async function exportAllPhoneData() {
      try {
        showIslandNotification('导出中', '正在收集所有数据...', 'info');

        // 收集所有数据库表的数据
        const exportData = {
          version: '1.0.0',
          exportTime: new Date().toISOString(),
          appName: 'MobileSimulator',
          tables: {}
        };

        // 导出所有表
        const tableNames = [
          'chats',
          'chatSettings',
          'chatMessages',
          'chatSessions',
          'characterSchedules',
          'characterAffection',
          'characterDiary',
          'characterAlbums',
          'phoneNumbers',
          'apiConfig',
          'globalSettings',
          'worldBooks',
          'apiPresets',
          'userProfiles',
          'callRecords',
          'contacts'
        ];

        for (const tableName of tableNames) {
          try {
            if (db[tableName]) {
              const data = await db[tableName].toArray();
              exportData.tables[tableName] = data;
              console.log(`📦 导出 ${tableName}: ${data.length} 条记录`);
            }
          } catch (e) {
            console.warn(`⚠️ 导出 ${tableName} 失败:`, e.message);
            exportData.tables[tableName] = [];
          }
        }

        // 同时导出localStorage中的所有设置（包含外观app数据）
        exportData.localStorage = {};
        const localStorageKeys = [
          // 基础设置
          'theme',
          'superHtmlCardEnabled',
          'htmlCardEnabled',
          'stickerModeEnabled',
          'autoScheduleEnabled',

          // 聊天样式
          'chatAppStyle',
          'chatsBgType',
          'chatsBgSolid',
          'chatsBgGradientStart',
          'chatsBgGradientEnd',
          'chatsBgImage',

          // 主屏壁纸
          'homeWallpaper',
          'homeWallpaperGradient',
          'homeWallpaperDot',
          'homeWallpaperStyle',

          // 启动壁纸
          'bootWallpaper',
          'bootWallpaperGradient',
          'bootWallpaperDot',
          'bootWallpaperStyle',
          'bootAnimationType',

          // 字体设置
          'globalFont',
          'customFonts',

          // 手机外观
          'phoneColors',
          'phoneFrameSticker',

          // 好感度设置
          'affectionModeEnabled',
          'affectionIndicatorEnabled',
          'showAffectionReminder',
          'affectionIndicatorStyle',
          'customAffectionImage',

          // 布局和表情包
          'appGridLayout',
          'userStickers',
          'stickerCategories',

          // 🔥 【老王修复】遗漏的设置
          'customAppNames',        // 自定义App名称
          'fullscreenSettings',    // 全屏设置
          'baobaobookCategories',  // 百宝书分类
          'baobaobookEntries'      // 百宝书条目
        ];

        for (const key of localStorageKeys) {
          const value = localStorage.getItem(key);
          if (value !== null) {
            exportData.localStorage[key] = value;
          }
        }

        // 导出自定义图标（customIcon_xxx 格式的key）
        // 🔥 【老王修复】添加baobaobook
        const appNames = ['chat', 'api', 'settings', 'characters', 'phone', 'appearance', 'x', 'gallery', 'notes', 'clock', 'calendar', 'camera', 'music', 'calculator', 'weather', 'browser', 'baobaobook'];
        for (const appName of appNames) {
          const iconKey = `customIcon_${appName}`;
          const iconValue = localStorage.getItem(iconKey);
          if (iconValue) {
            exportData.localStorage[iconKey] = iconValue;
          }
        }

        // 生成文件名（包含时间戳）
        const now = new Date();
        const timestamp = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}`;
        const fileName = `phone_backup_${timestamp}.json`;

        // 创建并下载文件
        const jsonString = JSON.stringify(exportData, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);

        const link = document.createElement('a');
        link.href = url;
        link.download = fileName;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        // 计算数据统计
        let totalRecords = 0;
        for (const tableName in exportData.tables) {
          totalRecords += exportData.tables[tableName].length;
        }

        showIslandNotification('导出成功', `已导出 ${totalRecords} 条数据`, 'check');
        vibrateDevice();

        console.log('✅ 数据导出完成:', {
          文件名: fileName,
          总记录数: totalRecords,
          文件大小: `${(jsonString.length / 1024).toFixed(2)} KB`
        });

      } catch (error) {
        console.error('❌ 导出数据失败:', error);
        showIslandNotification('导出失败', error.message, 'info');
      }
    }

    /**
     * 导入全部手机数据
     * 从备份文件恢复所有数据（会覆盖现有数据）
     * 使用删除数据库再重建的方式，避免IndexedDB锁定问题
     */
    async function importAllPhoneData() {
      try {
        // 先确认用户是否要覆盖数据
        const confirmed = confirm(
          '⚠️ 警告：导入数据将覆盖现有的所有数据！\n\n' +
          '此操作不可撤销，建议先导出当前数据作为备份。\n\n' +
          '确定要继续吗？'
        );

        if (!confirmed) return;

        // 创建文件选择器
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json';

        input.onchange = async (e) => {
          const file = e.target.files[0];
          if (!file) return;

          try {
            showIslandNotification('导入中', '正在读取文件...', 'info');

            // 🔥 【老王优化】读取文件内容
            const text = await file.text();
            const fileSize = (text.length / 1024 / 1024).toFixed(2);
            console.log(`📦 文件大小: ${fileSize} MB`);

            const importData = JSON.parse(text);

            // 验证数据格式
            if (!importData.version || !importData.tables) {
              throw new Error('无效的备份文件格式');
            }

            if (importData.appName !== 'MobileSimulator') {
              throw new Error('此文件不是有效的手机模拟器备份');
            }

            // 🔥 【老王重构】直接清空并导入，不用localStorage中转（避免配额限制）
            console.log('🗑️ 开始清空现有数据...');
            showIslandNotification('导入中', '正在清理旧数据...', 'info');

            // 定义所有表名（按依赖顺序）
            const tableNames = [
              'chats', 'chatSettings', 'chatSessions', 'chatMessages',
              'characterSchedules', 'characterAffection', 'characterDiary', 'characterAlbums',
              'phoneNumbers', 'callRecords', 'contacts',
              'apiConfig', 'globalSettings', 'worldBooks', 'apiPresets', 'userProfiles'
            ];

            // 清空所有表
            for (const tableName of tableNames) {
              if (db[tableName]) {
                await db[tableName].clear();
                console.log(`🧹 已清空表: ${tableName}`);
              }
            }

            console.log('✅ 旧数据已清空，开始导入新数据...');
            showIslandNotification('导入中', '正在写入数据...', 'info');

            // 🔥 【老王优化】按顺序导入，带进度统计
            let totalImported = 0;
            let tableCount = 0;

            for (const tableName of tableNames) {
              const records = importData.tables?.[tableName];
              if (!records || !Array.isArray(records) || records.length === 0) continue;

              try {
                if (!db[tableName]) {
                  console.warn(`⚠️ 表 ${tableName} 不存在，跳过`);
                  continue;
                }

                // 🔥 使用bulkPut导入（自动处理主键冲突）
                await db[tableName].bulkPut(records);
                totalImported += records.length;
                tableCount++;
                console.log(`✅ 导入 ${tableName}: ${records.length} 条记录`);
              } catch (e) {
                console.warn(`⚠️ 导入 ${tableName} 失败:`, e.message);
                // 🔥 配额错误特殊处理
                if (e.name === 'QuotaExceededError') {
                  throw new Error(`数据库存储配额不足！建议清理浏览器缓存或减少导入数据量。当前导入到表: ${tableName}`);
                }
              }
            }

            // 🔥 恢复localStorage设置（体积小，不会爆配额）
            if (importData.localStorage) {
              for (const key in importData.localStorage) {
                try {
                  // 跳过旧的pendingImportData（我们不再需要它）
                  if (key === '_pendingImportData') continue;
                  localStorage.setItem(key, importData.localStorage[key]);
                } catch (e) {
                  console.warn(`⚠️ 恢复localStorage失败 (${key}):`, e.message);
                }
              }
              console.log('📥 localStorage设置已恢复');
            }

            console.log(`🎉 数据导入完成！共恢复 ${tableCount} 张表，${totalImported} 条记录`);
            showIslandNotification('导入成功', `已恢复 ${totalImported} 条数据`, 'check');

            // 🔥 延迟刷新页面，让用户看到成功提示
            setTimeout(() => {
              console.log('🔄 刷新页面以完全应用新数据...');
              location.reload();
            }, 1500);

          } catch (parseError) {
            console.error('❌ 导入失败:', parseError);
            showIslandNotification('导入失败', parseError.message, 'error');
          }
        };

        input.click();

      } catch (error) {
        console.error('❌ 导入数据失败:', error);
        showIslandNotification('导入失败', error.message, 'error');
      }
    }

    /**
     * 🔥 【老王优化】清理旧的导入中转数据（兼容旧版本）
     * 新版本不再使用localStorage中转，这个函数只负责清理旧数据
     */
    async function checkPendingImport() {
      const pendingData = localStorage.getItem('_pendingImportData');
      if (pendingData) {
        console.log('🧹 检测到旧版本的导入中转数据，已清理');
        localStorage.removeItem('_pendingImportData');
      }
    }

    /**
     * 🔥 【老王新增】检测存储使用情况
     * 显示IndexedDB和localStorage的配额使用信息
     */
    async function checkStorageUsage() {
      try {
        const infoEl = document.getElementById('storageUsageInfo');
        if (!infoEl) return;

        infoEl.textContent = '正在检测...';

        // 1. 检测IndexedDB配额（现代浏览器）
        let quotaInfo = '';
        if (navigator.storage && navigator.storage.estimate) {
          const estimate = await navigator.storage.estimate();
          const usedMB = (estimate.usage / 1024 / 1024).toFixed(2);
          const quotaMB = (estimate.quota / 1024 / 1024).toFixed(2);
          const usagePercent = ((estimate.usage / estimate.quota) * 100).toFixed(1);

          quotaInfo = `数据库: ${usedMB} MB / ${quotaMB} MB (${usagePercent}%)`;
          console.log(`📊 存储使用: ${usedMB}MB / ${quotaMB}MB (${usagePercent}%)`);
        } else {
          quotaInfo = '浏览器不支持配额检测';
        }

        // 2. 检测localStorage使用情况（粗略估算）
        let localStorageSize = 0;
        for (let key in localStorage) {
          if (localStorage.hasOwnProperty(key)) {
            localStorageSize += localStorage[key].length + key.length;
          }
        }
        const localStorageMB = (localStorageSize / 1024 / 1024).toFixed(2);
        const localStorageInfo = `缓存: ${localStorageMB} MB`;

        // 3. 统计数据库记录数
        let totalRecords = 0;
        const tableNames = [
          'chats', 'chatSettings', 'chatSessions', 'chatMessages',
          'characterSchedules', 'characterAffection', 'characterDiary', 'characterAlbums',
          'phoneNumbers', 'callRecords', 'contacts',
          'apiConfig', 'globalSettings', 'worldBooks', 'apiPresets', 'userProfiles'
        ];

        for (const tableName of tableNames) {
          if (db[tableName]) {
            const count = await db[tableName].count();
            totalRecords += count;
          }
        }

        // 4. 更新显示
        infoEl.innerHTML = `
          ${quotaInfo}<br>
          ${localStorageInfo}<br>
          记录总数: ${totalRecords} 条
        `;

        console.log(`📊 LocalStorage: ${localStorageMB}MB, 数据库记录: ${totalRecords}条`);

      } catch (error) {
        console.error('❌ 检测存储使用情况失败:', error);
        const infoEl = document.getElementById('storageUsageInfo');
        if (infoEl) {
          infoEl.textContent = '检测失败，请刷新页面重试';
        }
      }
    }

    // ==========================================
    // 预设管理
    // ==========================================

    // 渲染预设下拉框
    async function renderPresetSelector() {
      try {
        const select = document.getElementById('presetSelect');
        const presets = await db.globalSettings.where('id').startsWith('preset_').toArray();

        select.innerHTML = '<option value="">-- 选择预设 --</option>';
        presets.forEach(preset => {
          const option = document.createElement('option');
          option.value = preset.id;
          option.textContent = preset.presetName || preset.id;
          select.appendChild(option);
        });
      } catch (error) {
        console.error('渲染预设选择器失败:', error);
      }
    }

    /**
     * 🔥 【老王优化】选择预设时自动加载（下拉框onchange触发）
     */
    async function handlePresetChange() {
      try {
        const select = document.getElementById('presetSelect');
        const presetId = select.value;

        // 如果选择的是空选项，不做任何操作
        if (!presetId) {
          console.log('📋 已切换到空预设，保持当前内容');
          return;
        }

        // 调用加载预设函数
        await loadSelectedPreset();
      } catch (error) {
        console.error('❌ 处理预设切换失败:', error);
      }
    }

    /**
     * 加载选中的预设（内部函数，不直接调用）
     */
    async function loadSelectedPreset() {
      try {
        const select = document.getElementById('presetSelect');
        const presetId = select.value;

        if (!presetId) {
          showIslandNotification('提示', '请先选择一个预设', 'info');
          return;
        }

        const preset = await db.globalSettings.get(presetId);
        if (!preset) {
          showIslandNotification('错误', '预设不存在', 'error');
          return;
        }

        // 加载世界观
        if (preset.worldview) {
          document.getElementById('worldviewName').value = preset.worldview.name || '';
          document.getElementById('worldviewDesc').value = preset.worldview.description || '';
        } else {
          // 清空世界观字段
          document.getElementById('worldviewName').value = '';
          document.getElementById('worldviewDesc').value = '';
        }

        // 加载知识库
        if (preset.knowledgeBooks && Array.isArray(preset.knowledgeBooks)) {
          // 清空现有知识库
          await db.worldBooks.clear();
          // 导入预设中的知识库
          for (const book of preset.knowledgeBooks) {
            await db.worldBooks.put(book);
          }
          await renderKnowledgeList();
        } else {
          // 清空知识库
          await db.worldBooks.clear();
          await renderKnowledgeList();
        }

        console.log(`✅ 已加载预设: ${preset.presetName}`);
        showIslandNotification('已加载', `预设: ${preset.presetName}`, 'check');
        vibrateDevice();
      } catch (error) {
        console.error('❌ 加载预设失败:', error);
        showIslandNotification('错误', '加载预设失败', 'error');
      }
    }

    /**
     * 🔥 【老王新增】更新当前选中的预设
     * 将当前的世界观和知识库保存回选中的预设
     */
    async function updateCurrentPreset() {
      try {
        const select = document.getElementById('presetSelect');
        const presetId = select.value;

        // 检查是否选择了预设
        if (!presetId) {
          showIslandNotification('提示', '请先选择要更新的预设', 'info');
          return;
        }

        // 获取现有预设
        const existingPreset = await db.globalSettings.get(presetId);
        if (!existingPreset) {
          showIslandNotification('错误', '预设不存在', 'error');
          return;
        }

        // 🔥 确认对话框（避免误操作）
        const confirmed = confirm(
          `确定要更新预设 "${existingPreset.presetName}" 吗？\n\n` +
          `当前的世界观和知识库内容将覆盖该预设。`
        );
        if (!confirmed) return;

        // 获取当前世界观
        const worldview = {
          name: document.getElementById('worldviewName').value.trim(),
          description: document.getElementById('worldviewDesc').value.trim()
        };

        // 获取当前知识库
        const knowledgeBooks = await db.worldBooks.toArray();

        // 更新预设（保留原有的id、presetName、createdAt）
        const updatedPreset = {
          ...existingPreset,
          worldview: worldview,
          knowledgeBooks: knowledgeBooks,
          updatedAt: new Date().toISOString()
        };

        await db.globalSettings.put(updatedPreset);
        console.log(`✅ 已更新预设: ${existingPreset.presetName}`);

        // 🔥 刷新下拉框（如果presetName改了的话）
        await renderPresetSelector();
        // 重新选中该预设
        select.value = presetId;

        showIslandNotification('已更新', `预设: ${existingPreset.presetName}`, 'check');
        vibrateDevice();
      } catch (error) {
        console.error('❌ 更新预设失败:', error);
        showIslandNotification('错误', '更新预设失败', 'error');
      }
    }

    // 显示预设管理模态框
    function showPresetManagerModal() {
      const modal = document.getElementById('presetManagerModal');
      document.getElementById('modalOverlay').classList.add('active');
      modal.classList.add('active');
    }

    // 保存当前为新预设
    async function saveAsNewPreset() {
      try {
        const presetName = prompt('请输入预设名称:');
        if (!presetName || !presetName.trim()) return;

        // 获取当前世界观
        const worldview = {
          name: document.getElementById('worldviewName').value.trim(),
          description: document.getElementById('worldviewDesc').value.trim()
        };

        // 获取当前知识库
        const knowledgeBooks = await db.worldBooks.toArray();

        const preset = {
          id: `preset_${Date.now()}`,
          presetName: presetName.trim(),
          worldview: worldview,
          knowledgeBooks: knowledgeBooks,
          createdAt: new Date().toISOString()
        };

        await db.globalSettings.put(preset);
        await renderPresetSelector();
        closePresetManagerModal();

        showIslandNotification('成功', '预设已保存', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('保存预设失败:', error);
        showIslandNotification('错误', '保存预设失败', 'info');
      }
    }

    // 删除选中的预设
    async function deleteSelectedPreset() {
      try {
        const select = document.getElementById('presetSelect');
        const presetId = select.value;

        if (!presetId) {
          showIslandNotification('提示', '请先选择一个预设', 'info');
          return;
        }

        const preset = await db.globalSettings.get(presetId);
        if (!preset) {
          showIslandNotification('错误', '预设不存在', 'info');
          return;
        }

        const confirmed = confirm(`确定要删除预设 "${preset.presetName}" 吗？`);
        if (!confirmed) return;

        await db.globalSettings.delete(presetId);
        await renderPresetSelector();
        closePresetManagerModal();

        showIslandNotification('已删除', '预设已删除', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('删除预设失败:', error);
        showIslandNotification('错误', '删除预设失败', 'info');
      }
    }

    // 关闭预设管理模态框
    function closePresetManagerModal() {
      const modal = document.getElementById('presetManagerModal');
      document.getElementById('modalOverlay').classList.remove('active');
      modal.classList.remove('active');
    }

    // ==========================================
    // 初始化Settings页面
    // ==========================================
    async function initSettingsPage() {
      await loadWorldview();
      await renderKnowledgeList();
      await renderPresetSelector();
      // 🔥 【老王新增】自动检测存储使用情况
      await checkStorageUsage();
    }

