    // 加载API配置
    async function loadAPIConfig() {
      try {
        const apiConfig = await db.apiConfig.get('main');
        if (apiConfig) {
          document.getElementById('apiProxyUrl').value = apiConfig.proxyUrl || '';
          document.getElementById('apiKey').value = apiConfig.apiKey || '';

          // 处理模型选择框
          const modelSelect = document.getElementById('apiModel');
          const savedModel = apiConfig.model || '';

          if (savedModel) {
            // 检查选择框中是否已有该模型选项
            const existingOption = Array.from(modelSelect.options).find(opt => opt.value === savedModel);

            if (!existingOption) {
              // 如果没有，添加一个选项
              const option = document.createElement('option');
              option.value = savedModel;
              option.textContent = savedModel;
              modelSelect.appendChild(option);
            }

            // 选中该模型
            modelSelect.value = savedModel;
          }
        }
      } catch (error) {
        console.error('加载API配置失败:', error);
      }
    }

    // 保存API配置
    async function saveAPIConfig() {
      try {
        const proxyUrl = document.getElementById('apiProxyUrl').value.trim();
        const apiKey = document.getElementById('apiKey').value.trim();
        const model = document.getElementById('apiModel').value.trim();

        if (!proxyUrl || !apiKey || !model) {
          showIslandNotification('错误', '请填写完整的API配置', 'info');
          return;
        }

        await db.apiConfig.put({
          id: 'main',
          proxyUrl: proxyUrl,
          apiKey: apiKey,
          model: model,
          updatedAt: new Date().toISOString()
        });

        showIslandNotification('成功', 'API配置已保存', 'check');
        vibrateDevice();
      } catch (error) {
        console.error('保存API配置失败:', error);
        showIslandNotification('错误', '保存失败', 'info');
      }
    }

    // 清空API配置
    function clearAPIConfig() {
      document.getElementById('apiProxyUrl').value = '';
      document.getElementById('apiKey').value = '';
      const modelSelect = document.getElementById('apiModel');
      modelSelect.innerHTML = '<option value="">-- 请先拉取模型列表 --</option>';
      showIslandNotification('已清空', 'API配置已清空', 'info');
    }

    // 拉取可用模型列表
    async function fetchAvailableModels() {
      try {
        const proxyUrl = document.getElementById('apiProxyUrl').value.trim();
        const apiKey = document.getElementById('apiKey').value.trim();

        if (!proxyUrl || !apiKey) {
          showIslandNotification('错误', '请先填写API地址和密钥', 'info');
          return;
        }

        showIslandNotification('拉取中', '正在获取模型列表...', 'info');

        const modelSelect = document.getElementById('apiModel');
        modelSelect.innerHTML = '<option value="">加载中...</option>';

        // 判断是否为Gemini API
        const isGemini = proxyUrl.includes('generativelanguage');
        let models = [];

        if (isGemini) {
          // Gemini API - 拉取模型列表
          const geminiUrl = `https://generativelanguage.googleapis.com/v1beta/models?key=${apiKey}`;
          const response = await fetch(geminiUrl);

          if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
          }

          const data = await response.json();

          // Gemini返回格式: { models: [{ name: "models/gemini-pro", ... }] }
          if (data.models && Array.isArray(data.models)) {
            models = data.models
              .filter(m => m.supportedGenerationMethods && m.supportedGenerationMethods.includes('generateContent'))
              .map(m => {
                // 提取模型ID (移除 "models/" 前缀)
                const modelId = m.name.replace('models/', '');
                return {
                  id: modelId,
                  name: m.displayName || modelId
                };
              });
          }
        } else {
          // OpenAI兼容API - 拉取模型列表
          const response = await fetch(`${proxyUrl}/v1/models`, {
            method: 'GET',
            headers: {
              'Authorization': `Bearer ${apiKey}`
            }
          });

          if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
          }

          const data = await response.json();

          // OpenAI返回格式: { data: [{ id: "gpt-3.5-turbo", ... }] }
          if (data.data && Array.isArray(data.data)) {
            models = data.data.map(m => ({
              id: m.id,
              name: m.id
            }));
          } else if (data.models && Array.isArray(data.models)) {
            // 有些兼容API用的是models字段
            models = data.models.map(m => ({
              id: m.id || m.model,
              name: m.id || m.model
            }));
          }
        }

        // 更新模型选择框
        if (models.length === 0) {
          modelSelect.innerHTML = '<option value="">未找到可用模型</option>';
          showIslandNotification('提示', '未找到可用模型', 'info');
          return;
        }

        modelSelect.innerHTML = '<option value="">-- 选择模型 --</option>';
        models.forEach(model => {
          const option = document.createElement('option');
          option.value = model.id;
          option.textContent = model.name;
          modelSelect.appendChild(option);
        });

        showIslandNotification('成功', `已加载 ${models.length} 个模型`, 'check');
        vibrateDevice();

      } catch (error) {
        console.error('拉取模型列表失败:', error);

        const modelSelect = document.getElementById('apiModel');
        modelSelect.innerHTML = '<option value="">拉取失败，请检查配置</option>';

        showIslandNotification('失败', '拉取模型列表失败', 'info');
      }
    }

    // 测试API连接
    async function testAPIConnection() {
      try {
        const proxyUrl = document.getElementById('apiProxyUrl').value.trim();
        const apiKey = document.getElementById('apiKey').value.trim();
        const model = document.getElementById('apiModel').value.trim();

        if (!proxyUrl || !apiKey || !model) {
          showIslandNotification('错误', '请先填写完整的API配置', 'info');
          return;
        }

        // 更新状态卡片为测试中
        const statusCard = document.getElementById('apiStatusCard');
        statusCard.innerHTML = `
          <div style="text-align: center; padding: 20px 0;">
            <div style="width: 48px; height: 48px; border: 3px solid var(--border-color); border-top-color: var(--accent-color); border-radius: 50%; margin: 0 auto 12px; animation: spin 1s linear infinite;"></div>
            <div style="font-size: 13px; color: var(--text-secondary); line-height: 1.6;">
              正在测试连接...<br/>请稍候
            </div>
          </div>
        `;

        showIslandNotification('测试中', '正在连接API...', 'info');

        // 判断是否为Gemini API
        const isGemini = proxyUrl.includes('generativelanguage');
        let response;

        if (isGemini) {
          // Gemini API测试
          const geminiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;
          response = await fetch(geminiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              contents: [{
                parts: [{ text: '你好，请回复"连接成功"' }]
              }],
              generationConfig: { temperature: 0.8 }
            })
          });
        } else {
          // OpenAI兼容API测试
          response = await fetch(`${proxyUrl}/v1/chat/completions`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify({
              model: model,
              messages: [{ role: 'user', content: '你好，请回复"连接成功"' }],
              temperature: 0.8
            })
          });
        }

        if (response.ok) {
          const data = await response.json();

          // 提取响应文本
          let aiResponse = '';
          if (isGemini && data.candidates && data.candidates[0]) {
            aiResponse = data.candidates[0].content.parts[0].text || '(无响应)';
          } else if (data.choices && data.choices[0]) {
            aiResponse = data.choices[0].message.content || '(无响应)';
          }

          // 更新状态卡片为成功
          statusCard.innerHTML = `
            <div style="text-align: center; padding: 20px 0;">
              <svg viewBox="0 0 24 24" style="width: 48px; height: 48px; stroke: #22c55e; fill: none; stroke-width: 2; margin: 0 auto 12px;">
                <circle cx="12" cy="12" r="10" />
                <path d="M9 12l2 2 4-4" stroke-linecap="round" />
              </svg>
              <div style="font-size: 14px; font-weight: 500; color: var(--text-primary); margin-bottom: 8px;">
                连接成功
              </div>
              <div style="font-size: 12px; color: var(--text-secondary); line-height: 1.6;">
                API响应: ${aiResponse.substring(0, 50)}${aiResponse.length > 50 ? '...' : ''}
              </div>
            </div>
          `;

          showIslandNotification('成功', 'API连接测试成功', 'check');
          vibrateDevice();
        } else {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
      } catch (error) {
        console.error('测试API连接失败:', error);

        // 更新状态卡片为失败
        const statusCard = document.getElementById('apiStatusCard');
        statusCard.innerHTML = `
          <div style="text-align: center; padding: 20px 0;">
            <svg viewBox="0 0 24 24" style="width: 48px; height: 48px; stroke: #ef4444; fill: none; stroke-width: 2; margin: 0 auto 12px;">
              <circle cx="12" cy="12" r="10" />
              <path d="M12 8v4M12 16h.01" stroke-linecap="round" />
            </svg>
            <div style="font-size: 14px; font-weight: 500; color: var(--text-primary); margin-bottom: 8px;">
              连接失败
            </div>
            <div style="font-size: 12px; color: var(--text-secondary); line-height: 1.6;">
              ${error.message || '请检查API配置是否正确'}
            </div>
          </div>
        `;

        showIslandNotification('失败', 'API连接失败', 'info');
      }
    }

