    /**
     * 加载选中的API预设（内部函数，不直接调用）
     */
    async function loadSelectedAPIPreset() {
      try {
        const select = document.getElementById('apiPresetSelect');
        const presetId = select.value;

        if (!presetId) {
          showIslandNotification('提示', '请先选择一个预设', 'info');
          return;
        }

        const preset = await db.apiPresets.get(parseInt(presetId));
        if (!preset) {
          showIslandNotification('错误', '预设不存在', 'error');
          return;
        }

        // 加载API配置
        document.getElementById('apiProxyUrl').value = preset.proxyUrl || '';
        document.getElementById('apiKey').value = preset.apiKey || '';

        // 处理模型选择框
        const modelSelect = document.getElementById('apiModel');
        const savedModel = preset.model || '';

        if (savedModel) {
          // 检查选择框中是否已有该模型选项
          const existingOption = Array.from(modelSelect.options).find(opt => opt.value === savedModel);

          if (!existingOption) {
            // 如果没有，添加一个选项
            const option = document.createElement('option');
            option.value = savedModel;
            option.textContent = savedModel;
            modelSelect.appendChild(option);
          }

          // 选中该模型
          modelSelect.value = savedModel;
        } else {
          // 清空模型选择
          modelSelect.value = '';
        }

        console.log(`✅ 已加载API预设: ${preset.name}`);
        showIslandNotification('已加载', `预设: ${preset.name}`, 'check');
        vibrateDevice();
      } catch (error) {
        console.error('❌ 加载API预设失败:', error);
        showIslandNotification('错误', '加载预设失败', 'error');
      }
    }

    /**
     * 🔥 【老王新增】更新当前选中的API预设
     */
    async function updateCurrentAPIPreset() {
      try {
        const select = document.getElementById('apiPresetSelect');
        const presetId = select.value;

        // 检查是否选择了预设
        if (!presetId) {
          showIslandNotification('提示', '请先选择要更新的预设', 'info');
          return;
        }

        // 获取现有预设
        const existingPreset = await db.apiPresets.get(parseInt(presetId));
        if (!existingPreset) {
          showIslandNotification('错误', '预设不存在', 'error');
          return;
        }

        // 🔥 确认对话框（避免误操作）
        const confirmed = confirm(
          `确定要更新API预设 "${existingPreset.name}" 吗？\n\n` +
          `当前的API配置将覆盖该预设。`
        );
        if (!confirmed) return;

        // 获取当前API配置
        const updatedPreset = {
          ...existingPreset,
          proxyUrl: document.getElementById('apiProxyUrl').value.trim(),
          apiKey: document.getElementById('apiKey').value.trim(),
          model: document.getElementById('apiModel').value.trim(),
          updatedAt: new Date().toISOString()
        };

        await db.apiPresets.put(updatedPreset);
        console.log(`✅ 已更新API预设: ${existingPreset.name}`);

        // 🔥 刷新下拉框
        await renderAPIPresetSelector();
        // 重新选中该预设
        select.value = presetId;

        showIslandNotification('已更新', `预设: ${existingPreset.name}`, 'check');
        vibrateDevice();
      } catch (error) {
        console.error('❌ 更新API预设失败:', error);
        showIslandNotification('错误', '更新预设失败', 'error');
      }
    }

