    // Update clock
    function updateClock() {
      const now = new Date();
      const hours = String(now.getHours()).padStart(2, '0');
      const minutes = String(now.getMinutes()).padStart(2, '0');
      const timeStr = `${hours}:${minutes}`;

      document.getElementById('clockTime').textContent = timeStr;
      document.getElementById('statusTime').textContent = timeStr;

      // 🔥 【老王新增】同步更新全局时间栏
      const globalStatusTime = document.getElementById('globalStatusTime');
      if (globalStatusTime) {
        globalStatusTime.textContent = timeStr;
      }

      const days = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
      const months = ['1月', '2月', '3月', '4月', '5月', '6月', '7月', '8月', '9月', '10月', '11月', '12月'];
      const dateStr = `${months[now.getMonth()]}${now.getDate()}日 ${days[now.getDay()]}`;
      document.getElementById('clockDate').textContent = dateStr;
    }

    updateClock();
    setInterval(updateClock, 1000);

    // Battery Status Monitoring
    async function updateBatteryStatus() {
      const batteryFill = document.getElementById('batteryFill');
      const batteryPercent = document.getElementById('batteryPercent');
      const batteryIcon = document.getElementById('batteryIcon');

      // 🔥 【老王新增】全局时间栏的电池元素
      const globalBatteryFill = document.getElementById('globalBatteryFill');
      const globalBatteryPercent = document.getElementById('globalBatteryPercent');

      try {
        // Try to get battery information (works on mobile devices and some laptops)
        if ('getBattery' in navigator) {
          const battery = await navigator.getBattery();

          const updateBatteryUI = () => {
            const level = Math.round(battery.level * 100);
            batteryPercent.textContent = `${level}%`;

            // Update battery fill width (14 is the max width of the fill rect)
            const fillWidth = (level / 100) * 14;
            batteryFill.setAttribute('width', fillWidth);

            // 🔥 【老王新增】同步更新全局时间栏电池
            if (globalBatteryPercent) globalBatteryPercent.textContent = `${level}%`;
            if (globalBatteryFill) globalBatteryFill.setAttribute('width', fillWidth);
          };

          // Initial update
          updateBatteryUI();

          // Listen for battery changes
          battery.addEventListener('levelchange', updateBatteryUI);
          battery.addEventListener('chargingchange', updateBatteryUI);
        } else {
          // Fallback: show 100% if battery API not available (desktop)
          batteryPercent.textContent = '100%';
          batteryFill.setAttribute('width', '14');

          // 🔥 【老王新增】同步更新全局时间栏电池（fallback）
          if (globalBatteryPercent) globalBatteryPercent.textContent = '100%';
          if (globalBatteryFill) globalBatteryFill.setAttribute('width', '14');
        }
      } catch (error) {
        // Fallback for unsupported browsers
        batteryPercent.textContent = '100%';
        batteryFill.setAttribute('width', '14');

        // 🔥 【老王新增】同步更新全局时间栏电池（error fallback）
        if (globalBatteryPercent) globalBatteryPercent.textContent = '100%';
        if (globalBatteryFill) globalBatteryFill.setAttribute('width', '14');
      }
    }

    updateBatteryStatus();

    // Theme toggle
    function toggleTheme() {
      const html = document.documentElement;
      const currentTheme = html.getAttribute('data-theme');
      const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
      html.setAttribute('data-theme', newTheme);
      localStorage.setItem('theme', newTheme);
    }

