    // 迁移函数：修复所有现有的日记本封面HTML尺寸问题
    async function migrateDiaryCoverHTML() {
      try {
        console.log('🔄 开始迁移日记本封面HTML...');

        // 查询所有type为'cover'且有coverHTML的记录
        const allCovers = await db.characterDiary
          .where('type')
          .equals('cover')
          .toArray();

        console.log(`📊 找到 ${allCovers.length} 条封面记录`);

        if (!allCovers || allCovers.length === 0) {
          console.log('❌ 没有找到需要迁移的封面记录');
          return { success: true, updated: 0, total: 0 };
        }

        let updatedCount = 0;
        let skippedCount = 0;
        const containerDiv = `<div style="width: 100%; height: 100%; overflow: hidden; position: relative; display: flex; flex-direction: column;">`;

        for (const cover of allCovers) {
          // 跳过没有coverHTML的记录
          if (!cover.coverHTML) {
            console.log(`⏭️ 跳过ID ${cover.id}：没有coverHTML`);
            skippedCount++;
            continue;
          }

          // 检查是否已经被包裹过（检查是否以包裹容器开头）
          const trimmedHTML = cover.coverHTML.trim();
          if (trimmedHTML.startsWith('<div style="width: 100%; height: 100%; overflow: hidden;')) {
            console.log(`⏭️ 跳过ID ${cover.id}：已经包裹过`);
            skippedCount++;
            continue;
          }

          // 包裹HTML
          const wrappedHTML = `${containerDiv}
    ${cover.coverHTML}
  </div>`;

          // 更新数据库
          await db.characterDiary.update(cover.id, {
            coverHTML: wrappedHTML,
            updatedAt: Date.now()
          });

          console.log(`✅ 已更新ID ${cover.id}`);
          updatedCount++;
        }

        console.log(`✅ 日记本封面HTML迁移完成：共${allCovers.length}条记录，更新了${updatedCount}条，跳过了${skippedCount}条`);
        return { success: true, updated: updatedCount, total: allCovers.length, skipped: skippedCount };
      } catch (error) {
        console.error('❌ 日记本封面HTML迁移失败:', error);
        return { success: false, error: error.message };
      }
    }

