        // 🔥 【老王新增】合并角色绑定、聊天框绑定、情景默认的百宝书条目
        // 优先级：角色绑定 > 聊天框绑定 > 情景默认（都添加，只是顺序）
        const allBoundBaobaobookEntries = [...boundBaobaobookEntries];
        const existingIds = new Set(boundBaobaobookEntries.map(e => e.id));

        // 添加聊天框绑定的条目（去重）
