    /**
     * 🔥 图片压缩函数 - 支持透明度保持
     * @param {string} base64 - 原始base64图片
     * @param {number} maxWidth - 最大宽度（默认1280）
     * @param {number} maxHeight - 最大高度（默认1280）
     * @param {number} quality - JPEG压缩质量0-1（默认0.7，仅对JPEG有效）
     * @param {boolean} preserveTransparency - 是否保持透明度（true=PNG格式，false=JPEG格式）
     * @returns {Promise<string>} - 压缩后的base64
     */
    function compressImage(base64, maxWidth = 1280, maxHeight = 1280, quality = 0.7, preserveTransparency = false) {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = function() {
          let { width, height } = img;

          // 计算缩放比例，保持宽高比
          if (width > maxWidth || height > maxHeight) {
            const ratio = Math.min(maxWidth / width, maxHeight / height);
            width = Math.round(width * ratio);
            height = Math.round(height * ratio);
          }

          // 用canvas压缩
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          // 🔥 如果需要保持透明度，清空画布（默认是透明的）
          if (preserveTransparency) {
            ctx.clearRect(0, 0, width, height);
          }

          ctx.drawImage(img, 0, 0, width, height);

          // 🔥 根据是否需要透明度选择输出格式
          let compressed;
          if (preserveTransparency) {
            // PNG格式保持透明度
            compressed = canvas.toDataURL('image/png');
            console.log(`[图标压缩-PNG] 原始: ${(base64.length / 1024).toFixed(1)}KB → 压缩后: ${(compressed.length / 1024).toFixed(1)}KB`);
          } else {
            // JPEG格式压缩效果好（用于壁纸等不需要透明度的图片）
            compressed = canvas.toDataURL('image/jpeg', quality);
            console.log(`[壁纸压缩-JPEG] 原始: ${(base64.length / 1024).toFixed(1)}KB → 压缩后: ${(compressed.length / 1024).toFixed(1)}KB`);
          }
          resolve(compressed);
        };
        img.onerror = () => reject(new Error('图片加载失败'));
        img.src = base64;
      });
    }

    /**
     * 处理壁纸文件上传 - 支持指定类别（带压缩和错误处理）
     * @param {Event} event - 文件输入事件
     * @param {string} category - 'home' 或 'boot'
     */
    function handleWallpaperUpload(event, category) {
      const file = event.target.files[0];
      if (!file) return;

      // 检查文件类型
      if (!file.type.startsWith('image/')) {
        showIslandNotification('错误', '请选择图片文件！', 'info');
        return;
      }

      // 读取文件
      const reader = new FileReader();
      reader.onload = async function(e) {
        const originalBase64 = e.target.result;

        try {
          // 压缩图片防止配额超限（1920尺寸+0.85质量，保证清晰度）
          const compressedUrl = await compressImage(originalBase64, 1920, 1920, 0.85);

          // 保存到localStorage（带错误处理）
          const storageKey = category === 'home' ? 'homeWallpaper' : 'bootWallpaper';
          try {
            localStorage.setItem(storageKey, compressedUrl);
          } catch (storageError) {
            // localStorage还是超限了，尝试更小尺寸（仍保持较高质量）
            console.warn('[壁纸] 首次压缩后仍超限，尝试更小尺寸...');
            const smallerUrl = await compressImage(originalBase64, 1280, 1280, 0.75);
            try {
              localStorage.setItem(storageKey, smallerUrl);
            } catch (finalError) {
              showIslandNotification('错误', '图片太大，存储空间不足！请清理一些数据后重试', 'info');
              console.error('[壁纸] localStorage配额超限:', finalError);
              return;
            }
          }

          // 更新预览
          const previewId = category === 'home' ? 'homeWallpaperPreview' : 'bootWallpaperPreview';
          const preview = document.getElementById(previewId);
          const savedUrl = localStorage.getItem(storageKey); // 获取实际存储的URL
          if (preview) {
            preview.style.backgroundImage = `url(${savedUrl})`;
          }

          // 应用到实际页面
          if (category === 'home') {
            applyHomeWallpaper(savedUrl);
          } else {
            applyBootWallpaper(savedUrl);
          }

          const label = category === 'home' ? '主屏壁纸' : '开机壁纸';
          showIslandNotification('成功', `${label}已应用！`, 'check');
        } catch (error) {
          console.error('[壁纸] 处理失败:', error);
          showIslandNotification('错误', '壁纸处理失败，请重试！', 'info');
        }
      };
      reader.readAsDataURL(file);

      // 重置input，允许重复选择同一文件
      event.target.value = '';
    }

