    // 🔥 删除随机陌生人号码（清理所有相关数据）
    async function deleteStrangerNumber() {
      if (!currentContactData) return;
      if (!currentContactData.isStranger || !currentContactData.strangerPersona) {
        showIslandNotification('错误', '这不是随机陌生人号码', 'error');
        return;
      }

      const phoneNumber = currentContactData.phoneNumber;
      const strangerName = currentContactData.strangerPersona.name || phoneNumber;

      // 二次确认
      if (!confirm(`确定要删除此号码 "${phoneNumber}" 吗？\n\n这是随机陌生人 "${strangerName}"，删除后：\n- 该号码的所有数据将被清除\n- 再次拨打此号码会生成新的随机人设\n- 此操作无法撤销！`)) {
        return;
      }

      try {
        console.log('📱 删除随机陌生人号码:', phoneNumber, '陌生人:', strangerName);

        let deletedCount = 0;

        // 1. 删除contacts记录
        await db.contacts.delete(phoneNumber);
        console.log('✅ 已删除contacts记录');
        deletedCount++;

        // 2. 删除callRecords中phoneNumber匹配的记录
        if (db.callRecords) {
          const allCallRecords = await db.callRecords.toArray();
          const recordsToDelete = allCallRecords.filter(r => normalizeId(r.phoneNumber) === normalizeId(phoneNumber));
          for (const record of recordsToDelete) {
            await db.callRecords.delete(record.id);
          }
          console.log(`✅ 已删除callRecords: ${recordsToDelete.length} 条`);
          deletedCount += recordsToDelete.length;
        }

        // 3. 删除chatMessages中phoneNumber匹配的记录（type='call'或'sms'）
        if (db.chatMessages) {
          const allMessages = await db.chatMessages.toArray();
          const messagesToDelete = allMessages.filter(m =>
            normalizeId(m.phoneNumber) === normalizeId(phoneNumber) &&
            (m.type === 'call' || m.type === 'sms')
          );
          for (const msg of messagesToDelete) {
            await db.chatMessages.delete(msg.id);
          }
          console.log(`✅ 已删除chatMessages: ${messagesToDelete.length} 条`);
          deletedCount += messagesToDelete.length;
        }

        // 关闭详情页
        hideContactDetail();

        // 刷新phone相关界面
        console.log('🔄 刷新phone相关界面');
        setTimeout(() => {
          if (typeof renderContactsList === 'function') {
            renderContactsList();
          }
          if (typeof renderCallRecords === 'function') {
            renderCallRecords();
          }
        }, 400);

        showIslandNotification('删除成功', `已删除号码 "${phoneNumber}" 及所有相关数据（${deletedCount}条）`, 'info');

      } catch (error) {
        console.error('❌ 删除随机陌生人号码失败:', error);
        showIslandNotification('删除失败', '请重试', 'error');
      }
    }

