    // 获取置顶联系人数据（后续由用户实现具体逻辑）
    function getImessagePinnedContacts() {
      // 默认返回空数组，后续用户会告诉具体逻辑
      return [];
    }

    // 获取短信列表数据（从数据库读取所有SMS会话）
    async function getImessageMessages() {
      try {
        console.log('📱 [iMessage] 加载短信会话列表...');

        // 从chatMessages表获取所有短信（type='sms'的记录）
        const allMessages = await db.chatMessages.toArray();

        // 过滤出所有短信记录（sessionId以'sms_'开头）
        const smsMessages = allMessages.filter(msg => {
          const sessionId = normalizeId(msg.sessionId) || '';
          return sessionId.startsWith('sms_');
        });

        console.log('📱 [iMessage] 找到短信记录:', smsMessages.length, '条');

        if (smsMessages.length === 0) {
          return [];
        }

        // 按sessionId（号码）分组，找出每个会话的最后一条消息
        const conversationMap = new Map();

        smsMessages.forEach(msg => {
          const sessionId = normalizeId(msg.sessionId);
          const phoneNumber = sessionId.replace('sms_', '');

          if (!conversationMap.has(phoneNumber)) {
            conversationMap.set(phoneNumber, {
              phoneNumber: phoneNumber,
              messages: [],
              lastTimestamp: 0
            });
          }

          const conv = conversationMap.get(phoneNumber);
          conv.messages.push(msg);

          const msgTime = new Date(msg.timestamp).getTime();
          if (msgTime > conv.lastTimestamp) {
            conv.lastTimestamp = msgTime;
            conv.lastMessage = msg;
          }
        });

        console.log('📱 [iMessage] 找到会话数:', conversationMap.size);

        // 获取每个会话的联系人信息
        const conversations = [];

        for (const [phoneNumber, conv] of conversationMap) {
          // 查询联系人表获取名称和头像
          let contactName = phoneNumber;
          let contactAvatar = null;
          let avatarClass = 'imessage-avatar-gray';

          try {
            const contact = await db.contacts.get(phoneNumber);
            if (contact) {
              contactName = contact.nickname || phoneNumber;
              contactAvatar = contact.contactAvatar || null;
              // 根据名字首字母决定颜色
              const firstChar = contactName.charAt(0).toLowerCase();
              if ('aeiou'.includes(firstChar)) {
                avatarClass = 'imessage-avatar-pink';
              } else if ('wxyz'.includes(firstChar)) {
                avatarClass = 'imessage-avatar-blue';
              }
            }
          } catch (e) {
            console.log('📱 [iMessage] 未找到联系人:', phoneNumber);
          }

          // 格式化最后消息时间
          const lastTime = new Date(conv.lastTimestamp);
          const timeStr = formatImessageTime(lastTime);

          // 获取最后一条消息内容预览
          let preview = conv.lastMessage?.content || '';
          if (preview.length > 40) {
            preview = preview.substring(0, 40) + '...';
          }

          // 获取首字母作为默认头像
          const initial = contactName.charAt(0).toUpperCase();

          conversations.push({
            id: phoneNumber, // 使用电话号码作为ID
            name: contactName,
            avatar: contactAvatar,
            avatarClass: avatarClass,
            initial: initial,
            time: timeStr,
            preview: preview,
            unread: false, // 后续可以实现未读状态
            heart: null, // 后续可以根据角色关系决定
            lastTimestamp: conv.lastTimestamp
          });
        }

        // 按最后消息时间排序（最新的在前）
        conversations.sort((a, b) => b.lastTimestamp - a.lastTimestamp);

        console.log('📱 [iMessage] 返回会话列表:', conversations.length, '个');
        return conversations;

      } catch (error) {
        console.error('❌ [iMessage] 加载短信列表失败:', error);
        return [];
      }
    }

    // 格式化iMessage时间显示
    function formatImessageTime(date) {
      const now = new Date();
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const yesterday = new Date(today.getTime() - 24 * 60 * 60 * 1000);
      const msgDate = new Date(date.getFullYear(), date.getMonth(), date.getDate());

      if (msgDate.getTime() === today.getTime()) {
        // 今天，显示时间
        return date.toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
          hour12: true
        });
      } else if (msgDate.getTime() === yesterday.getTime()) {
        // 昨天
        return 'Yesterday';
      } else if (now.getTime() - date.getTime() < 7 * 24 * 60 * 60 * 1000) {
        // 一周内，显示星期几
        return date.toLocaleDateString('en-US', { weekday: 'long' });
      } else {
        // 更早，显示日期
        return date.toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric'
        });
      }
    }

    // 打开短信聊天详情（从iMessage列表点击进入）
    async function openImessageChat(phoneNumber) {
      console.log('📱 [iMessage] 打开短信聊天:', phoneNumber);

      try {
        // 标记SMS是从iMessage进入的
        smsOpenedFrom = 'imessage';

        // 获取联系人名称（用于SMS详情页标题）
        let contactName = phoneNumber;

        const contact = await db.contacts.get(phoneNumber);
        if (contact) {
          contactName = contact.nickname || phoneNumber;
        }

        // 🔥 关键修复：smsDetailScreen在phoneScreen内部，必须先激活phoneScreen
        // 否则SMS页面虽然有active类，但因为父容器隐藏所以看不到
        const phoneScreen = document.getElementById('phoneScreen');
        if (phoneScreen) {
          phoneScreen.classList.add('active');
        }

        // 关闭iMessage列表页
        const imessageScreen = document.getElementById('imessageScreen');
        if (imessageScreen) {
          imessageScreen.classList.remove('active');
        }

        // 调用现有的openSmsDetail函数打开短信详情页
        await openSmsDetail(phoneNumber, contactName);

      } catch (error) {
        console.error('❌ [iMessage] 打开短信聊天失败:', error);
        showIslandNotification('错误', '无法打开短信', 'error');
      }
    }

    console.log('✅ iMessage模块加载完成');

    // ==================== End iMessage App ====================

    // ==================== BaoBaoBook Category Management - 百宝书分类管理 ====================

    /**
     * 获取百宝书分类列表
     */
    function getBaobaobookCategories() {
      try {
        const categoriesJson = localStorage.getItem('baobaobookCategories');
        return categoriesJson ? JSON.parse(categoriesJson) : [];
      } catch (error) {
        console.error('[百宝书] 读取分类失败:', error);
        return [];
      }
    }

    /**
     * 保存百宝书分类列表
     */
    function saveBaobaobookCategories(categories) {
      try {
        localStorage.setItem('baobaobookCategories', JSON.stringify(categories));
        console.log('[百宝书] 分类已保存:', categories);
      } catch (error) {
        console.error('[百宝书] 保存分类失败:', error);
        showIslandNotification('错误', '保存分类失败', 'error');
      }
    }

    /**
     * 显示百宝书分类管理抽屉
     */
    function showBaobaobookCategoryManager() {
      console.log('[百宝书] 打开分类管理抽屉');
      const drawer = document.getElementById('baobaobookCategoryDrawerOverlay');
      if (drawer) {
        drawer.classList.add('active');
        loadBaobaobookCategoryList();
        vibrateDevice();
      }
    }

    /**
     * 关闭百宝书分类管理抽屉
     */
    function closeBaobaobookCategoryManager() {
      console.log('[百宝书] 关闭分类管理抽屉');
      const drawer = document.getElementById('baobaobookCategoryDrawerOverlay');
      if (drawer) {
        drawer.classList.remove('active');
        vibrateDevice();
      }
    }

    /**
     * 加载分类列表到管理弹窗
     */
    function loadBaobaobookCategoryList() {
      const categories = getBaobaobookCategories();
      const listContainer = document.getElementById('baobaobookCategoryManagementList');

      if (!listContainer) return;

      if (categories.length === 0) {
        listContainer.innerHTML = `
          <div class="category-empty-state">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" style="width: 48px; height: 48px; opacity: 0.3; margin: 0 auto 12px;">
              <path d="M12 3h7a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-7m0-18H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h7m0-18v18" stroke-linecap="round" stroke-linejoin="round" />
            </svg>
            <div style="font-size: 13px; color: var(--text-tertiary);">还没有分类</div>
            <div style="font-size: 12px; color: var(--text-tertiary); margin-top: 4px;">在下方输入框创建你的第一个分类</div>
          </div>
        `;
        return;
      }

      let html = '';
      categories.forEach((category, index) => {
        html += `
          <div class="category-item" data-category="${category.name}">
            <div class="category-item-info">
              <div class="category-item-name">${category.name}</div>
              <div class="category-item-meta">${new Date(category.createdAt).toLocaleDateString()}</div>
            </div>
            <div class="category-item-actions">
              <button class="category-item-btn edit" onclick="renameBaobaobookCategoryPrompt('${category.name}')" title="重命名">
                <svg viewBox="0 0 24 24">
                  <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" stroke-linecap="round" stroke-linejoin="round"/>
                  <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
              </button>
              <button class="category-item-btn delete" onclick="deleteBaobaobookCategoryWithConfirm('${category.name}')" title="删除">
                <svg viewBox="0 0 24 24">
                  <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
              </button>
            </div>
          </div>
        `;
      });

      listContainer.innerHTML = html;
    }

    /**
     * 创建新分类
     */
    function createBaobaobookCategory() {
      const input = document.getElementById('baobaobookNewCategoryNameInput');
      if (!input) return;

      const categoryName = input.value.trim();

      // 验证：不能为空
      if (!categoryName) {
        showIslandNotification('提示', '分类名称不能为空', 'info');
        return;
      }

      // 验证：长度限制
      if (categoryName.length < 1 || categoryName.length > 20) {
        showIslandNotification('提示', '分类名称长度应在1-20字符之间', 'info');
        return;
      }

      // 验证：不能重复
      const categories = getBaobaobookCategories();
      if (categories.some(cat => cat.name === categoryName)) {
        showIslandNotification('提示', '分类名称已存在', 'info');
        return;
      }

      // 创建新分类
      const newCategory = {
        id: 'cat_' + Date.now(),
        name: categoryName,
        createdAt: Date.now()
      };

      categories.push(newCategory);
      saveBaobaobookCategories(categories);

      // 刷新列表
      loadBaobaobookCategoryList();
      updateBaobaobookCategoryTabs();

      // 清空输入框
      input.value = '';

      showIslandNotification('成功', `分类"${categoryName}"已创建`, 'check');
      vibrateDevice();

      console.log('[百宝书] 创建分类:', newCategory);
    }

    /**
     * 删除分类（带确认）
     */
    function deleteBaobaobookCategoryWithConfirm(categoryName) {
      // 使用irregular-modal进行确认
      const confirmHtml = `
        <div class="irregular-modal active" id="deleteCategoryConfirmModal">
          <div class="modal-title">确认删除</div>
          <div class="modal-content">
            <p style="font-size: 14px; color: var(--text-secondary); line-height: 1.6;">
              确定要删除分类"${categoryName}"吗？<br>
              该分类下的条目将被移到未分类。
            </p>
          </div>
          <div class="modal-actions">
            <div class="modal-btn" onclick="closeDeleteCategoryConfirm()">取消</div>
            <div class="modal-btn primary" onclick="confirmDeleteBaobaobookCategory('${categoryName}')">删除</div>
          </div>
        </div>
      `;

      // 添加到body
      const tempDiv = document.createElement('div');
      tempDiv.innerHTML = confirmHtml;
      document.body.appendChild(tempDiv.firstElementChild);
    }

    /**
     * 关闭删除确认弹窗
     */
    window.closeDeleteCategoryConfirm = function() {
      const modal = document.getElementById('deleteCategoryConfirmModal');
      if (modal) {
        modal.classList.remove('active');
        setTimeout(() => modal.remove(), 300);
      }
    };

    /**
     * 确认删除分类
     */
    window.confirmDeleteBaobaobookCategory = function(categoryName) {
      const categories = getBaobaobookCategories();
      const filteredCategories = categories.filter(cat => cat.name !== categoryName);

      if (filteredCategories.length === categories.length) {
        showIslandNotification('错误', '分类不存在', 'error');
        closeDeleteCategoryConfirm();
        return;
      }

      saveBaobaobookCategories(filteredCategories);

      // TODO: 将该分类下的条目移到"未分类"
      // 这部分需要在实现百宝书条目存储后完成

      // 刷新列表
      loadBaobaobookCategoryList();
      updateBaobaobookCategoryTabs();

      showIslandNotification('成功', `分类"${categoryName}"已删除`, 'check');
      vibrateDevice();

      closeDeleteCategoryConfirm();
      console.log('[百宝书] 删除分类:', categoryName);
    };

    /**
     * 重命名分类（显示输入框）
     */
    function renameBaobaobookCategoryPrompt(oldName) {
      const newName = prompt('请输入新的分类名称:', oldName);

      if (!newName || newName === oldName) {
        return;
      }

      const trimmedName = newName.trim();

      // 验证
      if (!trimmedName) {
        showIslandNotification('提示', '分类名称不能为空', 'info');
        return;
      }

      if (trimmedName.length < 1 || trimmedName.length > 20) {
        showIslandNotification('提示', '分类名称长度应在1-20字符之间', 'info');
        return;
      }

      // 检查重复
      const categories = getBaobaobookCategories();
      if (categories.some(cat => cat.name === trimmedName)) {
        showIslandNotification('提示', '分类名称已存在', 'info');
        return;
      }

      // 重命名
      const category = categories.find(cat => cat.name === oldName);
      if (category) {
        category.name = trimmedName;
        saveBaobaobookCategories(categories);

        // TODO: 更新该分类下所有条目的分类名称
        // 这部分需要在实现百宝书条目存储后完成

        loadBaobaobookCategoryList();
        updateBaobaobookCategoryTabs();

        showIslandNotification('成功', `分类已重命名为"${trimmedName}"`, 'check');
        vibrateDevice();

        console.log('[百宝书] 重命名分类:', oldName, '->', trimmedName);
      }
    }

    /**
     * 更新分类导航栏
     */
    function updateBaobaobookCategoryTabs() {
      const categories = getBaobaobookCategories();
      const tabsContainer = document.getElementById('baobaobookCategoryTabs');

      if (!tabsContainer) return;

      // 保留"全部"标签，添加其他分类标签
      let html = '<div class="worldview-tab active" data-category-id="all" onclick="filterBaobaobookByCategory(\'all\')">全部</div>';

      categories.forEach(category => {
        html += `<div class="worldview-tab" data-category-id="${category.id}" onclick="filterBaobaobookByCategory('${category.id}')">${category.name}</div>`;
      });

      tabsContainer.innerHTML = html;

      console.log('[百宝书] 分类导航栏已更新');
    }

    /**
     * 按分类筛选百宝书条目
     */
    function filterBaobaobookByCategory(categoryId) {
      console.log('[百宝书] 筛选分类ID:', categoryId);

      // 更新tab样式
      const tabs = document.querySelectorAll('#baobaobookCategoryTabs .worldview-tab');
      tabs.forEach(tab => {
        if (tab.getAttribute('data-category-id') === categoryId) {
          tab.classList.add('active');
        } else {
          tab.classList.remove('active');
        }
      });

      // 根据分类筛选并渲染百宝书条目
      renderBaobaobookEntries(categoryId);

      vibrateDevice();
    }

    // ==================== 百宝书条目管理 ====================

    /**
     * 获取百宝书条目列表
     */
    function getBaobaobookEntries() {
      try {
        const entriesData = localStorage.getItem('baobaobookEntries');
        return entriesData ? JSON.parse(entriesData) : [];
      } catch (error) {
        console.error('获取百宝书条目失败:', error);
        return [];
      }
    }

    /**
     * 保存百宝书条目列表
     */
    function saveBaobaobookEntries(entries) {
      try {
        localStorage.setItem('baobaobookEntries', JSON.stringify(entries));
        console.log('✅ 百宝书条目已保存:', entries.length);
      } catch (error) {
        console.error('❌ 保存百宝书条目失败:', error);
        showIslandNotification('错误', '保存失败，请稍后重试', 'info');
      }
    }

    // 当前编辑的条目ID（null表示新建模式）
    let currentEditingEntryId = null;

    /**
     * 加载分类选项到下拉框
     */
    function loadBaobaobookCategoryOptions(categorySelect, selectedCategoryId = null) {
      const categories = getBaobaobookCategories();
      categorySelect.innerHTML = '<option value="">请选择分类</option>';

      categories.forEach(cat => {
        const option = document.createElement('option');
        option.value = cat.id;
        option.textContent = cat.name;
        categorySelect.appendChild(option);
      });

      // 如果有指定分类，选中它
      if (selectedCategoryId) {
        categorySelect.value = selectedCategoryId;
      } else {
        // 否则尝试选中当前激活的分类
        const activeTab = document.querySelector('.worldview-tab.active[data-category-id]');
        if (activeTab) {
          const activeCategoryId = activeTab.dataset.categoryId;
          if (activeCategoryId && activeCategoryId !== 'all') {
            categorySelect.value = activeCategoryId;
          }
        }
      }
    }

    /**
     * 设置抽屉为创建模式
     */
    function setDrawerCreateMode() {
      document.querySelector('#baobaobookEntryDrawerTitleText').textContent = '新建条目';
      document.querySelector('#baobaobookEntryDrawerSubtitle').textContent = '记录你的知识到百宝书';

      const leftBtn = document.querySelector('#baobaobookEntryBtnLeft');
      leftBtn.textContent = '取消';
      leftBtn.className = 'baobaobook-entry-btn-cancel';
      leftBtn.onclick = closeCreateBaobaobookModal;
    }

    /**
     * 设置抽屉为编辑模式
     */
    function setDrawerEditMode() {
      document.querySelector('#baobaobookEntryDrawerTitleText').textContent = '编辑条目';
      document.querySelector('#baobaobookEntryDrawerSubtitle').textContent = '修改或删除这个知识条目';

      const leftBtn = document.querySelector('#baobaobookEntryBtnLeft');
      leftBtn.textContent = '删除';
      leftBtn.className = 'baobaobook-entry-btn-delete';
      leftBtn.onclick = deleteBaobaobookEntry;
    }

    /**
     * 打开新建条目抽屉
     */
    window.showCreateBaobaobookModal = function() {
      const overlay = document.querySelector('.baobaobook-entry-drawer-overlay');
      const categorySelect = document.querySelector('#baobaobookEntryCategorySelect');

      if (!overlay) {
        console.error('找不到条目抽屉');
        return;
      }

      // 设置为新建模式
      currentEditingEntryId = null;
      setDrawerCreateMode();

      // 清空表单
      document.querySelector('#baobaobookEntryNameInput').value = '';
      document.querySelector('#baobaobookEntryKeywordsInput').value = '';
      document.querySelector('#baobaobookEntryContentTextarea').value = '';
      updateBaobaobookCharCount();

      // 加载分类选项
      if (categorySelect) {
        loadBaobaobookCategoryOptions(categorySelect);
      }

      // 显示抽屉
      overlay.classList.add('active');
      vibrateDevice();

      // 聚焦到名称输入框
      setTimeout(() => {
        document.querySelector('#baobaobookEntryNameInput')?.focus();
      }, 300);
    };

    /**
     * 打开编辑条目抽屉
     */
    window.showEditBaobaobookModal = function(entryId) {
      const entries = getBaobaobookEntries();
      const entry = entries.find(e => e.id === entryId);

      if (!entry) {
        showIslandNotification('错误', '找不到该条目', 'error');
        return;
      }

      const overlay = document.querySelector('.baobaobook-entry-drawer-overlay');
      const categorySelect = document.querySelector('#baobaobookEntryCategorySelect');

      if (!overlay) {
        console.error('找不到条目抽屉');
        return;
      }

      // 设置为编辑模式
      currentEditingEntryId = entryId;
      setDrawerEditMode();

      // 填充表单数据
      document.querySelector('#baobaobookEntryNameInput').value = entry.name;
      document.querySelector('#baobaobookEntryKeywordsInput').value = entry.keywords.join(', ');
      document.querySelector('#baobaobookEntryContentTextarea').value = entry.content;
      updateBaobaobookCharCount();

      // 加载分类选项并选中当前分类
      if (categorySelect) {
        loadBaobaobookCategoryOptions(categorySelect, entry.categoryId);
      }

      // 🔥 设置插入位置选择器
      const positionSelect = document.querySelector('#baobaobookEntryPositionSelect');
      if (positionSelect) {
        positionSelect.value = entry.position || 'middle';
      }

      // 🔥 设置情景默认使用复选框
      const defaultScenes = entry.defaultScenes || [];
      const sceneChatCheckbox = document.querySelector('#baobaobookEntrySceneChat');
      const sceneCallCheckbox = document.querySelector('#baobaobookEntrySceneCall');
      const sceneSmsCheckbox = document.querySelector('#baobaobookEntrySceneSms');
      if (sceneChatCheckbox) sceneChatCheckbox.checked = defaultScenes.includes('chat');
      if (sceneCallCheckbox) sceneCallCheckbox.checked = defaultScenes.includes('call');
      if (sceneSmsCheckbox) sceneSmsCheckbox.checked = defaultScenes.includes('sms');

      // 显示抽屉
      overlay.classList.add('active');
      vibrateDevice();
    };

    /**
     * 关闭条目抽屉
     */
    window.closeCreateBaobaobookModal = function() {
      const overlay = document.querySelector('.baobaobook-entry-drawer-overlay');
      if (overlay) {
        overlay.classList.remove('active');
        currentEditingEntryId = null;
        vibrateDevice();
      }
    };

    /**
     * 更新字符计数器
     */
    window.updateBaobaobookCharCount = function() {
      const textarea = document.querySelector('#baobaobookEntryContentTextarea');
      const counter = document.querySelector('#baobaobookEntryCharCount');

      if (textarea && counter) {
        const count = textarea.value.length;
        counter.textContent = count;
      }
    };

    /**
     * 保存百宝书条目（支持创建和更新）
     */
    window.saveBaobaobookEntry = function() {
      const nameInput = document.querySelector('#baobaobookEntryNameInput');
      const keywordsInput = document.querySelector('#baobaobookEntryKeywordsInput');
      const categorySelect = document.querySelector('#baobaobookEntryCategorySelect');
      const positionSelect = document.querySelector('#baobaobookEntryPositionSelect');
      const contentTextarea = document.querySelector('#baobaobookEntryContentTextarea');

      // 🔥 情景默认使用复选框
      const sceneChatCheckbox = document.querySelector('#baobaobookEntrySceneChat');
      const sceneCallCheckbox = document.querySelector('#baobaobookEntrySceneCall');
      const sceneSmsCheckbox = document.querySelector('#baobaobookEntrySceneSms');

      // 验证表单
      const name = nameInput.value.trim();
      if (!name) {
        showIslandNotification('提示', '请输入条目名称', 'info');
        nameInput.focus();
        vibrateDevice();
        return;
      }

      if (name.length > 50) {
        showIslandNotification('提示', '条目名称不能超过50个字符', 'info');
        nameInput.focus();
        vibrateDevice();
        return;
      }

      const content = contentTextarea.value.trim();
      if (!content) {
        showIslandNotification('提示', '请输入条目内容', 'info');
        contentTextarea.focus();
        vibrateDevice();
        return;
      }

      // 处理关键词
      const keywords = keywordsInput.value.trim()
        .split(',')
        .map(k => k.trim())
        .filter(k => k);

      // 🔥 收集选中的情景
      const defaultScenes = [];
      if (sceneChatCheckbox && sceneChatCheckbox.checked) defaultScenes.push('chat');
      if (sceneCallCheckbox && sceneCallCheckbox.checked) defaultScenes.push('call');
      if (sceneSmsCheckbox && sceneSmsCheckbox.checked) defaultScenes.push('sms');

      const entries = getBaobaobookEntries();

      if (currentEditingEntryId) {
        // 更新模式
        const entryIndex = entries.findIndex(e => e.id === currentEditingEntryId);
        if (entryIndex === -1) {
          showIslandNotification('错误', '找不到该条目', 'error');
          return;
        }

        entries[entryIndex].name = name;
        entries[entryIndex].keywords = keywords;
        entries[entryIndex].categoryId = categorySelect.value || '';
        entries[entryIndex].position = positionSelect.value || 'middle';
        entries[entryIndex].defaultScenes = defaultScenes;
        entries[entryIndex].content = content;
        entries[entryIndex].updatedAt = Date.now();

        saveBaobaobookEntries(entries);
        showIslandNotification('成功', '条目已更新', 'check');
      } else {
        // 创建模式
        const newEntry = {
          id: 'entry_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9),
          name: name,
          keywords: keywords,
          categoryId: categorySelect.value || '',
          position: positionSelect.value || 'middle',
          defaultScenes: defaultScenes,
          content: content,
          createdAt: Date.now(),
          updatedAt: Date.now()
        };

        entries.push(newEntry);
        saveBaobaobookEntries(entries);
        showIslandNotification('成功', '条目创建成功', 'check');
      }

      // 关闭抽屉
      closeCreateBaobaobookModal();

      // 刷新显示
      const activeTab = document.querySelector('.worldview-tab.active[data-category-id]');
      const currentCategoryId = activeTab ? activeTab.dataset.categoryId : 'all';
      renderBaobaobookEntries(currentCategoryId);

      vibrateDevice();
    };

    /**
     * 删除百宝书条目
     */
    window.deleteBaobaobookEntry = function() {
      if (!currentEditingEntryId) return;

      // 二次确认
      if (!confirm('确定要删除这个条目吗？此操作不可恢复。')) {
        return;
      }

      const entries = getBaobaobookEntries();
      const filteredEntries = entries.filter(e => e.id !== currentEditingEntryId);

      if (filteredEntries.length === entries.length) {
        showIslandNotification('错误', '找不到该条目', 'error');
        return;
      }

      saveBaobaobookEntries(filteredEntries);

      // 关闭抽屉
      closeCreateBaobaobookModal();

      // 刷新显示
      const activeTab = document.querySelector('.worldview-tab.active[data-category-id]');
      const currentCategoryId = activeTab ? activeTab.dataset.categoryId : 'all';
      renderBaobaobookEntries(currentCategoryId);

      showIslandNotification('成功', '条目已删除', 'check');
      vibrateDevice();
    };

    /**
     * 渲染百宝书条目列表 - 紧凑列表式布局
     */
    function renderBaobaobookEntries(categoryId = 'all') {
      const container = document.querySelector('#baobaobookGrid');
      if (!container) {
        console.error('找不到百宝书容器');
        return;
      }

      const allEntries = getBaobaobookEntries();

      // 根据分类筛选
      let filteredEntries = allEntries;
      if (categoryId && categoryId !== 'all') {
        filteredEntries = allEntries.filter(entry => entry.categoryId === categoryId);
      }

      // 清空容器
      container.innerHTML = '';

      // 创建按钮 - 虚线边框样式
      const createBtn = document.createElement('div');
      createBtn.className = 'baobaobook-create-entry-btn';
      createBtn.onclick = showCreateBaobaobookModal;
      createBtn.innerHTML = `
        <svg viewBox="0 0 24 24">
          <path d="M12 4v16m8-8H4" stroke-linecap="round" stroke-linejoin="round"/>
        </svg>
        <span>新建条目</span>
      `;
      container.appendChild(createBtn);

      // 如果没有条目，显示空状态提示
      if (filteredEntries.length === 0) {
        const emptyState = document.createElement('div');
        emptyState.className = 'baobaobook-empty-state';
        emptyState.innerHTML = `
          <div class="baobaobook-empty-icon">
            <svg viewBox="0 0 24 24">
              <path d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" stroke-linecap="round" stroke-linejoin="round"/>
            </svg>
          </div>
          <div class="baobaobook-empty-text">暂无知识条目</div>
        `;
        container.appendChild(emptyState);
        return;
      }

      // 创建列表容器
      const list = document.createElement('div');
      list.className = 'baobaobook-entry-list';

      // 获取所有分类用于显示分类名
      const categories = getBaobaobookCategories();

      // 渲染条目列表
      filteredEntries.forEach(entry => {
        const item = document.createElement('div');
        item.className = 'baobaobook-entry-item';
        item.dataset.entryId = entry.id;

        // 获取分类名称
        const category = categories.find(c => c.id === entry.categoryId);
        const categoryName = category ? category.name : '未分类';

        // 获取首字母作为头像
        const initial = entry.name.charAt(0).toUpperCase();

        // 关键词标签（最多显示3个）
        const keywordTags = entry.keywords.slice(0, 3).map(kw =>
          `<span class="baobaobook-entry-keyword">${escapeHtml(kw)}</span>`
        ).join('');

        // 内容预览（最多60字符）
        const preview = entry.content.length > 60
          ? entry.content.substring(0, 60) + '...'
          : entry.content;

        item.innerHTML = `
          <div class="baobaobook-entry-avatar">${initial}</div>
          <div class="baobaobook-entry-info">
            <div class="baobaobook-entry-header">
              <div class="baobaobook-entry-name">${escapeHtml(entry.name)}</div>
              <div class="baobaobook-entry-category">${escapeHtml(categoryName)}</div>
            </div>
            ${entry.keywords.length > 0 ? `<div class="baobaobook-entry-keywords">${keywordTags}</div>` : ''}
            <div class="baobaobook-entry-preview">${escapeHtml(preview)}</div>
          </div>
        `;

        // 点击查看详情
        item.addEventListener('click', () => {
          showBaobaobookEntryDetail(entry.id);
        });

        list.appendChild(item);
      });

      container.appendChild(list);
      console.log(`渲染 ${filteredEntries.length} 个百宝书条目`);
    }

    /**
     * 显示条目详情（打开编辑弹窗）
     */
    function showBaobaobookEntryDetail(entryId) {
      showEditBaobaobookModal(entryId);
    }

    // 监听textarea输入事件，更新字符计数
    const entryContentTextarea = document.querySelector('#baobaobookEntryContentTextarea');
    if (entryContentTextarea) {
      entryContentTextarea.addEventListener('input', updateBaobaobookCharCount);
    }

    // 监听抽屉overlay点击，点击背景关闭
    const createOverlay = document.querySelector('.baobaobook-entry-drawer-overlay');
    if (createOverlay) {
      createOverlay.addEventListener('click', (e) => {
        if (e.target === createOverlay) {
          closeCreateBaobaobookModal();
        }
      });
    }

    console.log('✅ 百宝书分类管理模块加载完成');
    console.log('✅ 百宝书条目管理模块加载完成');

    // ==========================================
    // Mmpages (Threads Profile) 功能
    // ==========================================

    let currentMmpagesCharacter = null;

    // 打开Mmpages页面
    async function openMmpages() {
      console.log('📱 打开Mmpages页面');

      const mmpagesScreen = document.getElementById('mmpagesScreen');
      if (!mmpagesScreen) {
        console.error('❌ 找不到mmpagesScreen元素');
        return;
      }

      // 从数据库重新加载当前角色数据（确保是最新的）
      if (currentCharProfileData && currentCharProfileData.id) {
        try {
          const freshCharacter = await db.chats.get(currentCharProfileData.id);
          if (freshCharacter) {
            loadMmpagesData(freshCharacter);
          } else {
            loadMmpagesData(currentCharProfileData);
          }
        } catch (error) {
          console.error('❌ 加载角色数据失败:', error);
          loadMmpagesData(currentCharProfileData);
        }
      } else {
        console.warn('⚠️ 当前没有角色数据');
      }

      // 显示mmpages
      mmpagesScreen.classList.add('active');

      // 最后关闭角色功能卡片
      closeCharProfile();
    }

    // 关闭Mmpages页面
    function closeMmpages() {
      console.log('📱 关闭Mmpages页面');

      const mmpagesScreen = document.getElementById('mmpagesScreen');
      if (mmpagesScreen) {
        mmpagesScreen.classList.remove('active');
      }
    }

    // 加载角色数据到Mmpages页面
    function loadMmpagesData(character) {
      console.log('📊 加载角色数据到Mmpages:', character.name);

      currentMmpagesCharacter = character;

      // 更新个人资料信息
      const displayName = document.getElementById('mmpagesDisplayName');
      const username = document.getElementById('mmpagesUsername');
      const bio = document.getElementById('mmpagesBio');
      const bioNote = document.getElementById('mmpagesBioNote');
      const followers = document.getElementById('mmpagesFollowers');
      const avatar = document.getElementById('mmpagesAvatar');

      if (displayName) displayName.textContent = character.name || 'Character Name';

      // 使用保存的用户名或自动生成
      const autoUsername = (character.name || 'username').toLowerCase().replace(/\s+/g, '_');
      if (username) username.textContent = '@' + (character.mmpagesUsername || autoUsername);

      // 使用保存的bio或角色设定
      if (bio) {
        if (character.mmpagesBio) {
          bio.textContent = character.mmpagesBio;
        } else {
          const charSettings = character.settings?.charSettings || '';
          const firstLine = charSettings.split('\n')[0] || 'No bio available';
          bio.textContent = firstLine.substring(0, 100);
        }
      }

      // 使用保存的bio备注或默认值
      if (bioNote) bioNote.textContent = character.mmpagesBioNote || '~ Not impersonating anyone!';

      // 使用保存的粉丝数或随机生成
      if (followers) {
        const followersCount = character.mmpagesFollowers || Math.floor(Math.random() * 500) + 100;
        followers.textContent = followersCount + 'K followers';
      }

      if (avatar) {
        const avatarSrc = character.avatar || character.settings?.aiAvatar || '';
        avatar.src = avatarSrc;
        avatar.onerror = function() {
          this.style.display = 'none';
          this.parentNode.textContent = '?';
        };
      }

      // 渲染示例Posts
      renderMmpagesPosts(character);

      // 初始化Tabs功能
      initMmpagesTabs();
    }

    // 渲染Posts（动态生成）
    function renderMmpagesPosts(character) {
      const postsContainer = document.getElementById('mmpagesPostsContainer');
      const emptyState = document.getElementById('mmpagesEmptyState');
      if (!postsContainer) return;

      // 清除之前的帖子（保留空状态）
      const existingPosts = postsContainer.querySelectorAll('.mmpages-post');
      existingPosts.forEach(post => post.remove());

      // 从角色数据中获取帖子（目前为空，后续可扩展）
      const posts = character.mmpagesPosts || [];

      // 如果没有帖子，显示空状态
      if (posts.length === 0) {
        if (emptyState) emptyState.style.display = 'flex';
        return;
      }

      // 有帖子时，隐藏空状态
      if (emptyState) emptyState.style.display = 'none';

      // 生成帖子HTML
      let postsHTML = '';
      posts.forEach(post => {
        postsHTML += generateMmpagesPostHTML(post, character);
      });

      // 插入到空状态后面
      const emptyStateElement = document.getElementById('mmpagesEmptyState');
      if (emptyStateElement) {
        emptyStateElement.insertAdjacentHTML('afterend', postsHTML);
      }

      // 初始化点赞功能
      initMmpagesLikes();
    }

    // 生成单个帖子的HTML
    function generateMmpagesPostHTML(post, character) {
      const username = post.username || (character.name || 'User').replace(/\s+/g, '_').toLowerCase();
      const avatar = post.avatar || character.avatar || character.settings?.aiAvatar || '';
      const showFollowBadge = post.showFollowBadge !== false;

      // 处理图片
      let imagesHTML = '';
      if (post.images && post.images.length > 0) {
        imagesHTML = '<div class="mmpages-post-images">';
        post.images.forEach(img => {
          if (typeof img === 'string') {
            // URL 字符串
            imagesHTML += `<div class="mmpages-post-image" style="background-image: url('${img}'); background-size: cover; background-position: center;"></div>`;
          } else if (img.url) {
            // 对象格式 {url: string, class?: string}
            imagesHTML += `<div class="mmpages-post-image ${img.class || ''}" style="background-image: url('${img.url}'); background-size: cover; background-position: center;"></div>`;
          } else {
            // 占位图片
            imagesHTML += `<div class="mmpages-post-image ${img.class || ''}"></div>`;
          }
        });
        imagesHTML += '</div>';
      }

      return `
        <article class="mmpages-post">
          <div class="mmpages-post-header">
            <div class="mmpages-post-avatar-wrapper">
              <div class="mmpages-post-avatar">
                <img src="${avatar}" alt="Avatar" onerror="this.style.display='none'">
              </div>
              ${showFollowBadge ? `
                <div class="mmpages-follow-badge">
                  <svg viewBox="0 0 24 24">
                    <path d="M12 5v14"/>
                    <path d="M5 12h14"/>
                  </svg>
                </div>
              ` : ''}
            </div>
            <div class="mmpages-post-content">
              <div class="mmpages-post-top-row">
                <div class="mmpages-post-user-time">
                  <span class="mmpages-post-username">${username}</span>
                  <span class="mmpages-post-time">${post.time || '1d'}</span>
                </div>
                <div class="mmpages-post-more">
                  <span></span><span></span><span></span>
                </div>
              </div>
              <p class="mmpages-post-text">${post.text || ''}</p>
              ${imagesHTML}
              <div class="mmpages-post-actions">
                <div class="mmpages-action-btn mmpages-like-btn">
                  <svg viewBox="0 0 24 24">
                    <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                  </svg>
                  <span>${post.likes || '0'}</span>
                </div>
                <div class="mmpages-action-btn">
                  <svg viewBox="0 0 24 24">
                    <path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/>
                  </svg>
                  <span>${post.comments || '0'}</span>
                </div>
                <div class="mmpages-action-btn">
                  <svg viewBox="0 0 24 24">
                    <path d="M20 11a8.1 8.1 0 0 0-15.5-2m-.5-4v4h4"/>
                    <path d="M4 13a8.1 8.1 0 0 0 15.5 2m.5 4v-4h-4"/>
                  </svg>
                  <span>${post.reposts || '0'}</span>
                </div>
                <div class="mmpages-action-btn">
                  <svg viewBox="0 0 24 24">
                    <path d="M4.698 4.034l16.302 7.966l-16.302 7.966a.503 .503 0 0 1 -.546 -.124a.555 .555 0 0 1 -.12 -.568l2.468 -7.274l-2.468 -7.274a.555 .555 0 0 1 .12 -.568a.503 .503 0 0 1 .546 -.124z"/>
                    <path d="M6.5 12h14.5"/>
                  </svg>
                  <span>${post.shares || '0'}</span>
                </div>
              </div>
            </div>
          </div>
        </article>
      `;
    }

    // 添加帖子到当前角色（供外部调用）
    function addMmpagesPost(postData) {
      if (!currentMmpagesCharacter) {
        console.warn('⚠️ 没有当前Mmpages角色');
        return;
      }

      // 初始化帖子数组
      if (!currentMmpagesCharacter.mmpagesPosts) {
        currentMmpagesCharacter.mmpagesPosts = [];
      }

      // 添加帖子
      currentMmpagesCharacter.mmpagesPosts.unshift(postData);

      // 重新渲染
      renderMmpagesPosts(currentMmpagesCharacter);
    }

    // 初始化Tabs切换功能
    function initMmpagesTabs() {
      const tabs = document.querySelectorAll('.mmpages-tab');
      tabs.forEach(tab => {
        tab.addEventListener('click', function() {
          // 移除所有active类
          tabs.forEach(t => t.classList.remove('active'));
          // 添加active类到当前tab
          this.classList.add('active');

          const tabType = this.getAttribute('data-tab');
          console.log('📑 切换到Tab:', tabType);

          // TODO: 根据不同tab加载不同内容
          // 目前只显示示例posts
        });
      });
    }

    // 初始化点赞功能
    function initMmpagesLikes() {
      const likeBtns = document.querySelectorAll('.mmpages-like-btn');
      likeBtns.forEach(btn => {
        btn.addEventListener('click', function() {
          const svg = this.querySelector('svg');
          if (this.classList.toggle('liked')) {
            svg.style.fill = '#ff3b5c';
            svg.style.stroke = '#ff3b5c';
          } else {
            svg.style.fill = 'none';
            svg.style.stroke = 'var(--text-primary)';
          }
        });
      });
    }

    // ==========================================
    // Mmpages Edit Modal 相关功能
    // ==========================================

    let mmpagesEditAvatar = null;

    // 打开编辑弹窗
    async function openMmpagesEditModal() {
      console.log('📝 打开Mmpages编辑弹窗');

      const overlay = document.getElementById('mmpagesEditOverlay');
      if (!overlay) return;

      // 从数据库重新加载最新数据
      if (currentMmpagesCharacter && currentMmpagesCharacter.id) {
        try {
          const freshCharacter = await db.chats.get(currentMmpagesCharacter.id);
          if (freshCharacter) {
            currentMmpagesCharacter = freshCharacter;
          }
        } catch (error) {
          console.error('❌ 加载最新角色数据失败:', error);
        }
      }

      // 加载当前角色数据到表单
      if (currentMmpagesCharacter) {
        const displayName = document.getElementById('mmpagesEditDisplayName');
        const username = document.getElementById('mmpagesEditUsername');
        const bio = document.getElementById('mmpagesEditBio');
        const bioNote = document.getElementById('mmpagesEditBioNote');
        const followers = document.getElementById('mmpagesEditFollowers');
        const avatarPreview = document.getElementById('mmpagesEditAvatarPreview');

        if (displayName) displayName.value = currentMmpagesCharacter.name || '';

        // 用户名自动从角色名生成
        const autoUsername = (currentMmpagesCharacter.name || 'username').toLowerCase().replace(/\s+/g, '_');
        if (username) username.value = currentMmpagesCharacter.mmpagesUsername || autoUsername;

        // Bio - 使用角色设定的第一行
        if (bio) {
          const charSettings = currentMmpagesCharacter.settings?.charSettings || '';
          const firstLine = charSettings.split('\n')[0] || '';
          bio.value = currentMmpagesCharacter.mmpagesBio || firstLine.substring(0, 100);
        }

        if (bioNote) bioNote.value = currentMmpagesCharacter.mmpagesBioNote || '~ Not impersonating anyone!';

        // 粉丝数（只显示数字部分）
        if (followers) {
          const followersCount = currentMmpagesCharacter.mmpagesFollowers || Math.floor(Math.random() * 500) + 100;
          followers.value = followersCount;
        }

        // 头像预览
        if (avatarPreview) {
          const avatarSrc = currentMmpagesCharacter.avatar || currentMmpagesCharacter.settings?.aiAvatar || '';
          avatarPreview.src = avatarSrc;
          mmpagesEditAvatar = null; // 清空临时头像，除非用户上传新的
        }
      }

      // 显示弹窗
      overlay.classList.add('active');
    }

    // 关闭编辑弹窗
    function closeMmpagesEditModal() {
      console.log('❌ 关闭Mmpages编辑弹窗');

      const overlay = document.getElementById('mmpagesEditOverlay');
      if (overlay) {
        overlay.classList.remove('active');
      }

      // 清空临时头像
      mmpagesEditAvatar = null;
    }

    // 处理头像上传
    function handleMmpagesAvatarUpload(event) {
      const file = event.target.files[0];
      if (!file) return;

      // 检查文件类型
      if (!file.type.startsWith('image/')) {
        alert('请选择图片文件');
        return;
      }

      // 读取文件并转换为 base64
      const reader = new FileReader();
      reader.onload = function(e) {
        const base64 = e.target.result;
        mmpagesEditAvatar = base64;

        // 更新预览
        const preview = document.getElementById('mmpagesEditAvatarPreview');
        if (preview) {
          preview.src = base64;
        }

        console.log('✅ 头像已上传');
      };
      reader.readAsDataURL(file);
    }

    // 保存编辑
    async function saveMmpagesEdit() {
      console.log('💾 保存Mmpages编辑');

      if (!currentMmpagesCharacter) {
        console.warn('⚠️ 没有当前角色');
        return;
      }

      // 获取表单数据
      const displayName = document.getElementById('mmpagesEditDisplayName')?.value || '';
      const username = document.getElementById('mmpagesEditUsername')?.value || '';
      const bio = document.getElementById('mmpagesEditBio')?.value || '';
      const bioNote = document.getElementById('mmpagesEditBioNote')?.value || '';
      const followers = document.getElementById('mmpagesEditFollowers')?.value || '0';

      // 验证必填字段
      if (!displayName.trim()) {
        alert('请输入名字');
        return;
      }

      // 保存到角色数据
      currentMmpagesCharacter.name = displayName.trim();
      currentMmpagesCharacter.originalName = displayName.trim();
      currentMmpagesCharacter.mmpagesUsername = username.trim() || displayName.toLowerCase().replace(/\s+/g, '_');
      currentMmpagesCharacter.mmpagesBio = bio.trim();
      currentMmpagesCharacter.mmpagesBioNote = bioNote.trim();
      currentMmpagesCharacter.mmpagesFollowers = parseInt(followers) || 0;

      // 保存头像（如果有更新）
      if (mmpagesEditAvatar) {
        currentMmpagesCharacter.avatar = mmpagesEditAvatar;
        // 更新settings中的aiAvatar
        if (!currentMmpagesCharacter.settings) {
          currentMmpagesCharacter.settings = {};
        }
        currentMmpagesCharacter.settings.aiAvatar = mmpagesEditAvatar;
      }

      // 保存到数据库
      try {
        const characterId = currentMmpagesCharacter.id;
        if (!characterId) {
          console.error('❌ 角色ID不存在');
          alert('保存失败：角色ID不存在');
          return;
        }

        // 更新时间戳
        currentMmpagesCharacter.updatedAt = Date.now();

        // 保存到数据库
        await db.chats.put(currentMmpagesCharacter);

        // 同步更新所有相关聊天的linkedCharacterData
        if (window.syncLinkedCharacterData) {
          await syncLinkedCharacterData(characterId, {
            name: currentMmpagesCharacter.name,
            originalName: currentMmpagesCharacter.originalName,
            settings: currentMmpagesCharacter.settings,
            mmpagesUsername: currentMmpagesCharacter.mmpagesUsername,
            mmpagesBio: currentMmpagesCharacter.mmpagesBio,
            mmpagesBioNote: currentMmpagesCharacter.mmpagesBioNote,
            mmpagesFollowers: currentMmpagesCharacter.mmpagesFollowers
          });
        }

        console.log('✅ Mmpages数据已保存到数据库');

        // 更新全局的currentCharProfileData（如果是同一个角色）
        if (window.currentCharProfileData && window.currentCharProfileData.id === characterId) {
          window.currentCharProfileData = currentMmpagesCharacter;
        }

        // 显示通知
        if (window.showIslandNotification) {
          showIslandNotification('主页已更新', `${currentMmpagesCharacter.name} 的主页信息已保存`, 'check');
        }

        // 更新显示
        loadMmpagesData(currentMmpagesCharacter);

        // 关闭弹窗
        closeMmpagesEditModal();
      } catch (error) {
        console.error('❌ 保存Mmpages数据失败:', error);
        alert('保存失败，请重试');
      }
    }

    console.log('✅ Mmpages功能模块加载完成');

